<body>
  <div class="card" role="region" aria-label="Interactive String Reverser">
    <div>
      <h1>Interactive String Reverser</h1>
      <p class="lead">Type below — reversed text updates in real time with per-character animation.</p>
    </div>

    <div class="input-row" style="width:100%;">
      <div class="field" role="group" aria-label="Input field">
        <input id="source" type="text" placeholder="Type something here..." autocomplete="off" aria-label="Source text" />
        <div class="controls" style="margin-left:8px;">
          <button id="clearBtn" class="btn" title="Clear input">Clear</button>
          <button id="copyBtn" class="btn" title="Copy reversed">Copy</button>
        </div>
      </div>

      <div class="meta" style="justify-content:center;">
        <div class="small" id="len">0 characters</div>
        <div class="small" id="info">Realtime · animated</div>
      </div>
    </div>

    <div class="display-area" aria-live="polite" aria-atomic="true">
      <div class="chars" id="chars" aria-hidden="false"></div>
    </div>

    <footer>
      <div class="small">Built for speed and clarity — enjoy.</div>
    </footer>
  </div>

<script>
(function(){
  const input = document.getElementById('source');
  const charsWrap = document.getElementById('chars');
  const lenLabel = document.getElementById('len');
  const clearBtn = document.getElementById('clearBtn');
  const copyBtn = document.getElementById('copyBtn');

  let last = '';
  let animCounter = 0;

  function updateMeta(text){
    const n = [...text].length;
    lenLabel.textContent = n + (n===1 ? ' character' : ' characters');
  }

  function reverseString(s){
    // correct reversing for surrogate pairs / combining marks using Array.from
    return Array.from(s).reverse().join('');
  }

  function renderReversed(rev){
    const newChars = Array.from(rev); // array of characters (handles unicode)
    const oldChars = Array.from(last);
    last = rev;

    // simple diff strategy: remove all and re-add with staggered animation.
    // This keeps character-by-character animation clear and predictable.
    // We'll animate leave for old nodes, then rebuild new nodes with enter animation.
    const existing = Array.from(charsWrap.children);

    // mark existing as leaving
    existing.forEach((node, i) => {
      node.classList.remove('enter','update');
      node.classList.add('leave');
      // remove after animation
      setTimeout(()=> {
        if (node.parentNode) node.parentNode.removeChild(node);
      }, 320 + i*12);
    });

    // add new nodes with slight stagger so each char animates in sequence
    newChars.forEach((ch, i) => {
      const span = document.createElement('div');
      span.className = 'char';
      span.textContent = ch === ' ' ? '\u00A0' : ch; // show non-breaking for spaces
      span.setAttribute('data-index', i);
      // staggered entrance
      setTimeout(()=> {
        charsWrap.appendChild(span);
        // trigger enter
        requestAnimationFrame(()=> {
          span.classList.add('enter');
        });
        // then a quick 'update' pulse to accent the change
        setTimeout(()=> {
          span.classList.add('update');
          setTimeout(()=> span.classList.remove('update'), 420);
        }, 80 + (i % 6) * 40);
      }, 60 + i * 40);
    });
  }

  let scheduled = null;
  function scheduleRender(){
    if (scheduled) cancelAnimationFrame(scheduled);
    scheduled = requestAnimationFrame(()=> {
      scheduled = null;
      const val = input.value;
      updateMeta(val);
      const rev = reverseString(val);
      renderReversed(rev);
    });
  }

  // initial
  scheduleRender();

  input.addEventListener('input', scheduleRender);
  input.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') e.preventDefault();
  });

  clearBtn.addEventListener('click', ()=> {
    input.value = '';
    input.focus();
    scheduleRender();
  });

  copyBtn.addEventListener('click', async ()=> {
    const rev = reverseString(input.value);
    try{
      await navigator.clipboard.writeText(rev);
      copyBtn.textContent = 'Copied';
      setTimeout(()=> copyBtn.textContent = 'Copy', 1200);
    }catch(err){
      // fallback
      const ta = document.createElement('textarea');
      ta.value = rev;
      document.body.appendChild(ta);
      ta.select();
      try{ document.execCommand('copy'); copyBtn.textContent = 'Copied'; }
      catch(e){ copyBtn.textContent = 'Failed'; }
      ta.remove();
      setTimeout(()=> copyBtn.textContent = 'Copy', 1200);
    }
  });

  // accessibility: announce changes for screen readers
  const live = document.querySelector('.display-area');
  const announce = (text) => {
    live.setAttribute('aria-label', 'Reversed: ' + text);
  };

  input.addEventListener('input', () => {
    announce(reverseString(input.value));
  });

  // small UX: focus input on load
  window.addEventListener('load', () => input.focus());
})();
</script>
</body>
</html>

If you want any changes — different animation speed, alternate visual style, or keeping cursor focus while animating — tell me which detail and I'll adjust it.

