    <div class="item"><div class="key found"></div><div class="small">Found</div></div>
  </div>

  <div class="status" id="status">Ready. Press Step to begin.</div>

  <div class="footer">Indices shown under boxes. Uses iterative binary search behavior: mid = Math.floor((low + high) / 2).</div>
</div>

<script>
(function(){
  // State
  let arr = [];
  let low = 0, high = -1, mid = -1;
  let target = null;
  let running = false;
  let timer = null;
  const arrayInput = document.getElementById('arrayInput');
  const loadBtn = document.getElementById('loadBtn');
  const arrayContainer = document.getElementById('arrayContainer');
  const status = document.getElementById('status');
  const targetInput = document.getElementById('targetInput');
  const stepBtn = document.getElementById('stepBtn');
  const runBtn = document.getElementById('runBtn');
  const resetBtn = document.getElementById('resetBtn');
  const shuffleBtn = document.getElementById('shuffleBtn');
  const randomBtn = document.getElementById('randomBtn');

  function parseArray(text){
    return text.split(',').map(s => s.trim()).filter(s => s !== '').map(s => {
      // try to parse numbers, otherwise keep strings
      const n = Number(s);
      return isNaN(n) ? s : n;
    });
  }

  function render(){
    arrayContainer.innerHTML = '';
    arr.forEach((v,i) => {
      const cell = document.createElement('div');
      cell.className = 'cell index';
      if (i < low || i > high) cell.classList.add('excluded');
      if (i >= low && i <= high) cell.classList.add('in-range');
      if (i === mid) cell.classList.add('mid');
      const val = document.createElement('div');
      val.textContent = String(v);
      const idx = document.createElement('div');
      idx.className = 'idx';
      idx.textContent = i;
      cell.appendChild(val);
      cell.appendChild(idx);
      if (i === mid && arr[i] === target){
        cell.classList.add('found');
      }
      arrayContainer.appendChild(cell);
    });

    if (low > high){
      status.innerHTML = '<strong>Done:</strong> Target ' + displayTarget() + ' not found. (low > high)';
    } else if (mid >= 0 && mid < arr.length && arr[mid] === target){
      status.innerHTML = '<strong>Found:</strong> Target ' + displayTarget() + ' at index ' + mid + '.';
    } else {
      status.innerHTML = '<strong>Searching:</strong> low = ' + low + ', high = ' + high + ', mid = ' + (mid>=0?mid:'-') + '.';
    }
  }

  function displayTarget(){
    return (typeof target === 'string')? ('"' + target + '"') : String(target);
  }

  function resetState(keepArray){
    if (!keepArray){
      arr = parseArray(arrayInput.value);
    }
    low = 0;
    high = arr.length - 1;
    mid = -1;
    target = parsePossibleNumber(targetInput.value);
    running = false;
    if (timer) { clearInterval(timer); timer = null; runBtn.textContent = 'Run'; }
    render();
    status.innerHTML = 'Ready. Press Step to begin.';
  }

  function parsePossibleNumber(s){
    if (s === null || s === undefined || s === '') return '';
    const n = Number(s);
    return isNaN(n) ? s.trim() : n;
  }

  function stepOnce(){
    if (arr.length === 0){
      status.innerHTML = '<strong>Error:</strong> Array is empty. Edit the array and press Load.';
      return;
    }
    if (target === '' || target === null || target === undefined){
      status.innerHTML = '<strong>Error:</strong> Target is empty. Enter a target value.';
      return;
    }
    if (low > high){
      // already finished not found
      render();
      return;
    }
    // compute mid
    mid = Math.floor((low + high) / 2);
    render();
    // check value
    const val = arr[mid];
    if (val === target){
      // found: mark and stop
      render();
      running = false;
      if (timer){ clearInterval(timer); timer = null; runBtn.textContent = 'Run'; }
      return;
    }
    // move bounds after a short delay to allow highlight to be seen
    // We'll perform bounds change immediately (user sees mid highlighted)
    if (compare(val, target) < 0){
      // val < target => search right half
      low = mid + 1;
    } else {
      // val > target => search left half
      high = mid - 1;
    }
    // if finished after update, re-render
    render();
  }

  function compare(a,b){
    // allow numeric and string compare. Prefer numeric if both are numbers
    const aNum = Number(a);
    const bNum = Number(b);
    if (!isNaN(aNum) && !isNaN(bNum)) {
      if (aNum < bNum) return -1;
      if (aNum > bNum) return 1;
      return 0;
    }
    // fallback to string compare
    const as = String(a);
    const bs = String(b);
    if (as < bs) return -1;
    if (as > bs) return 1;
    return 0;
  }

  // Controls
  loadBtn.addEventListener('click', () => {
    const parsed = parseArray(arrayInput.value);
    // ensure sorted order for meaningful binary search (sort numerically if numbers)
    const allNumbers = parsed.every(x => typeof x === 'number');
    if (allNumbers){
      parsed.sort((a,b)=>a-b);
    } else {
      parsed.sort(); // string sort
    }
    arr = parsed;
    // update input to show sorted
    arrayInput.value = arr.join(',');
    resetState(true);
  });

  stepBtn.addEventListener('click', () => {
    target = parsePossibleNumber(targetInput.value);
    stepOnce();
  });

  runBtn.addEventListener('click', () => {
    if (running){
      running = false;
      if (timer){ clearInterval(timer); timer = null; }
      runBtn.textContent = 'Run';
      status.innerHTML = 'Paused.';
      return;
    }
    // start
    target = parsePossibleNumber(targetInput.value);
    if (arr.length === 0){
      status.innerHTML = '<strong>Error:</strong> Array is empty. Load an array first.';
      return;
    }
    running = true;
    runBtn.textContent = 'Pause';
    timer = setInterval(() => {
      // stop if finished
      if (low > high) { running = false; clearInterval(timer); timer = null; runBtn.textContent = 'Run'; render(); return; }
      if (mid >=0 && mid < arr.length && arr[mid] === target){ running = false; clearInterval(timer); timer = null; runBtn.textContent = 'Run'; render(); return; }
      stepOnce();
    }, 650);
  });

  resetBtn.addEventListener('click', () => {
    // reset but keep current array
    resetState(true);
  });

  shuffleBtn.addEventListener('click', () => {
    // shuffle array values but keep unique sorted property not required; we'll randomize numbers
    const parsed = parseArray(arrayInput.value);
    // if numeric, create random numeric array from min..max
    const allNumbers = parsed.every(x => typeof x === 'number');
    if (allNumbers){
      const min = Math.min(...parsed);
      const max = Math.max(...parsed);
      const n = parsed.length;
      const out = [];
      for (let i=0;i<n;i++){
        out.push(Math.floor(Math.random()*(max - min + 1)) + min);
      }
      out.sort((a,b)=>a-b);
      arrayInput.value = out.join(',');
    } else {
      // randomize order and reassign indices
      for (let i = parsed.length -1; i>0; i--){
        const j = Math.floor(Math.random()*(i+1));
        [parsed[i], parsed[j]] = [parsed[j], parsed[i]];
      }
      arrayInput.value = parsed.join(',');
    }
    loadBtn.click();
  });

  randomBtn.addEventListener('click', () => {
    if (arr.length === 0) { status.innerHTML = '<strong>Error:</strong> Array is empty.'; return; }
    const allNumbers = arr.every(x => typeof x === 'number');
    if (allNumbers){
      const min = Math.min(...arr);
      const max = Math.max(...arr);
      const r = Math.floor(Math.random()*(max - min + 1)) + min;
      targetInput.value = r;
    } else {
      const r = arr[Math.floor(Math.random()*arr.length)];
      targetInput.value = String(r);
    }
    status.innerHTML = 'Random target set to ' + targetInput.value;
  });

  // initialize
  arr = parseArray(arrayInput.value);
  // ensure sorted
  if (arr.every(x=> typeof x === 'number')) arr.sort((a,b)=>a-b); else arr.sort();
  arrayInput.value = arr.join(',');
  resetState(true);

  // Accessibility: keyboard shortcuts
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Enter' && (document.activeElement === targetInput || document.activeElement === arrayInput)){
      loadBtn.click();
      e.preventDefault();
    } else if (e.key === 's' || e.key === 'S'){
      stepBtn.click();
    } else if (e.key === 'r' || e.key === 'R'){
      runBtn.click();
    } else if (e.key === 'Escape'){
      resetBtn.click();
    }
  });

})();
</script>
</body>
</html>
```

Notes:
- The visualizer expects a sorted array for correct binary-search behavior; the Load button sorts the values automatically.
- You can step one iteration at a time with Step, or Run to autoplay. The visualization highlights the in-range cells, the mid cell, and marks a found element.
- If you want any changes (different styling, show comparisons log, change mid formula to bias left/right, or support custom comparator), tell me and I’ll update it.

Here's a single self-contained HTML file that implements a working, interactive singly linked-list visualization. It uses SVG for clean arrows and boxes, supports insert-at-head, insert-at-tail, delete-by-value (first occurrence), and search with highlighting. Empty-list cases are handled, and the layout updates cleanly.

Save the text below as a file like linkedlist.html and open it in your browser.

<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1"/>
<title>Linked List Visualizer</title>
<style>
  body { font-family: system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial; margin: 20px; }
  h1 { margin: 0 0 12px 0; font-size: 20px; }
  .controls { display:flex; gap: 8px; flex-wrap:wrap; margin-bottom: 12px; align-items:center; }
  .controls input[type="text"] { padding:6px 8px; font-size:14px; width:140px; }
  .controls button { padding:8px 10px; font-size:14px; cursor:pointer; }
  .controls .info { margin-left: 6px; color:#555; font-size:13px; }
  #canvasWrap { border:1px solid #ddd; background:#fafafa; padding:12px; border-radius:6px; overflow:auto; }
  svg { width:100%; height:220px; display:block; }
  .node { cursor: default; }
  .node rect { fill:#fff; stroke:#333; stroke-width:1.4; rx:6; ry:6; }
  .node text { font-size:14px; pointer-events:none; fill:#111; }
  .node .value { font-weight:600; }
  .node .pointerBox { fill:#f3f7ff; stroke:#3b6df0; stroke-width:1; rx:5; ry:5; }
  .arrow { stroke:#3b6df0; stroke-width:2; fill:none; marker-end: url(#arrowhead); }
  .ghostArrow { stroke:#aaa; stroke-dasharray:4 6; opacity:0.6; }
  .highlight { filter: drop-shadow(0 0 6px rgba(59,109,240,0.6)); }
  .found rect { stroke: #27ae60; stroke-width:2.2; }
  .deleted rect { opacity:0.35; transition: opacity 0.4s; }
  .emptyMsg { fill:#777; font-size:14px; }
  .legend { margin-top:8px; color:#555; font-size:13px; }
  .status { margin-top:10px; color:#333; font-size:14px; min-height:18px; }
</style>
</head>
<body>
  <h1>Singly Linked List Visualizer</h1>

  <div class="controls">
    <input id="valueInput" type="text" placeholder="Value (string or number)"/>
    <button id="insertHeadBtn">Insert at head</button>
    <button id="insertTailBtn">Insert at tail</button>
    <input id="delInput" type="text" placeholder="Delete value"/>
    <button id="deleteBtn">Delete by value</button>
    <input id="searchInput" type="text" placeholder="Search value"/>
    <button id="searchBtn">Search</button>
    <button id="clearBtn">Clear list</button>
    <div class="info">Nodes are boxes with a pointer field on the right. Arrows show next pointers.</div>
  </div>

  <div id="canvasWrap">
    <svg id="svgCanvas" viewBox="0 0 1200 220" preserveAspectRatio="xMinYMin meet">
      <defs>
        <marker id="arrowhead" markerWidth="10" markerHeight="8" refX="9" refY="4" orient="auto">
          <path d="M0,0 L10,4 L0,8 z" fill="#3b6df0"></path>
        </marker>
      </defs>
      <!-- nodes and arrows will be inserted here -->
      <g id="content"></g>
    </svg>
  </div>

  <div class="legend">
    <strong>Legend:</strong>
    <span style="margin-left:8px;">Green border = found by search</span>
    <span style="margin-left:12px;">Dimmed = recently deleted</span>
  </div>

  <div class="status" id="status"></div>

<script>
(function(){
  const svg = document.getElementById('svgCanvas');
  const content = document.getElementById('content');
  const valueInput = document.getElementById('valueInput');
  const insertHeadBtn = document.getElementById('insertHeadBtn');
  const insertTailBtn = document.getElementById('insertTailBtn');
  const deleteBtn = document.getElementById('deleteBtn');
  const delInput = document.getElementById('delInput');
  const searchBtn = document.getElementById('searchBtn');
  const searchInput = document.getElementById('searchInput');
  const clearBtn = document.getElementById('clearBtn');
  const status = document.getElementById('status');

  // Simple linked list backend
  class Node {
    constructor(value){
      this.value = value;
      this.next = null;
      this.id = Node._nextId++;
    }
  }
  Node._nextId = 1;

  class LinkedList {
    constructor(){ this.head = null; this.size = 0; }
    insertHead(value){
      const n = new Node(value);
      n.next = this.head;
      this.head = n;
      this.size++;
      return n;
    }
    insertTail(value){
      const n = new Node(value);
      if(!this.head){ this.head = n; this.size++; return n; }
      let cur = this.head;
      while(cur.next) cur = cur.next;
      cur.next = n;
      this.size++;
      return n;
    }
    deleteByValue(value){
      if(!this.head) return null;
      if(same(this.head.value, value)){
        const removed = this.head;
        this.head = this.head.next;
        removed.next = null;
        this.size--;
        return removed;
      }
      let prev = this.head;
      let cur = this.head.next;
      while(cur){
        if(same(cur.value, value)){
          prev.next = cur.next;
          cur.next = null;
          this.size--;
          return cur;
        }
        prev = cur; cur = cur.next;
      }
      return null;
    }
    find(value){
      let idx=0;
      let cur=this.head;
      while(cur){
        if(same(cur.value, value)) return {node:cur, index: idx};
        cur=cur.next; idx++;
      }
      return null;
    }
    clear(){ this.head = null; this.size = 0; Node._nextId = 1; }
    toArray(){ const out=[]; let cur=this.head; while(cur){ out.push(cur); cur=cur.next; } return out; }
  }

  function same(a,b){
    // treat numbers and numeric strings equivalently if both numeric
    if(a === b) return true;
    const an = (typeof a === 'string' && a.trim()!=='' && !isNaN(a)) ? Number(a) : a;
    const bn = (typeof b === 'string' && b.trim()!=='' && !isNaN(b)) ? Number(b) : b;
    return an === bn;
  }

  const list = new LinkedList();

  // Rendering constants
  const NODE_W = 120;
  const NODE_H = 48;
  const PTR_W = 36;
  const GAP = 28;
  const START_X = 12;
  const START_Y = 20;

  function clearContent(){
    while(content.firstChild) content.removeChild(content.firstChild);
  }

  function render(){
    clearContent();
    const nodes = list.toArray();
    if(nodes.length === 0){
      // show "empty" message and a ghost head pointer that points to null
      const g = createSvg('g', {class:'node empty'});
      const x = START_X, y = START_Y;
      // box representing head pointer only
      const rect = createSvg('rect', {x:x, y:y, width:NODE_W, height:NODE_H, rx:6, ry:6, fill:'#fff', stroke:'#333', 'stroke-width':1.2});
      const txt = createSvg('text', {x:x + 12, y: y + NODE_H/2 + 5, 'class':'value', 'font-size':14});
      txt.textContent = 'Head: null';
      g.appendChild(rect); g.appendChild(txt);
      content.appendChild(g);
      // ghost arrow to indicate empty pointer (dashed)
      const gx = x + NODE_W - PTR_W/2;
      const arrow = createSvg('line', {x1: gx, y1: y + NODE_H/2, x2: gx + 120, y2: y + NODE_H/2, class:'arrow ghostArrow'});
      content.appendChild(arrow);
      const nullTxt = createSvg('text', {x: gx + 126, y: y + NODE_H/2 + 5, class:'emptyMsg'});
      nullTxt.textContent = 'null';
      content.appendChild(nullTxt);
      status.textContent = 'List is empty.';
      return;
    }

    // Render each node with pointer box
    const nodePositions = [];
    let x = START_X;
    let y = START_Y;
    nodes.forEach((n,i) => {
      nodePositions.push({node:n,x:x,y:y});
      const g = createSvg('g', {class:'node', id:'node-' + n.id});
      // whole box: value region and pointer region on the right
      const rect = createSvg('rect', {x:x, y:y, width:NODE_W, height:NODE_H, rx:6, ry:6});
      g.appendChild(rect);
      // pointer sub-box overlay at right
      const ptrX = x + NODE_W - PTR_W;
      const pbox = createSvg('rect', {x:ptrX + 6, y:y + 8, width:PTR_W - 12, height:NODE_H - 16, class:'pointerBox'});
      g.appendChild(pbox);
      // value text
      const txt = createSvg('text', {x:x + 12, y: y + NODE_H/2 + 5, 'class':'value'});
      txt.textContent = String(n.value);
      g.appendChild(txt);

      // label for index (optional small)
      const idxTxt = createSvg('text', {x:x + NODE_W/2 - 8, y: y + NODE_H + 16, 'font-size':12, 'fill':'#666'});
      idxTxt.textContent = 'Node';
      g.appendChild(idxTxt);

      content.appendChild(g);
      x += NODE_W + GAP;
    });

    // Now draw arrows from each node's pointer to next node (or to null)
    nodePositions.forEach((p,i) => {
      const fromX = p.x + NODE_W - PTR_W/2;
      const fromY = p.y + NODE_H/2;
      if(p.node.next){
        // find target position
        const target = nodePositions.find(q => q.node === p.node.next);
        if(target){
          const toX = target.x + PTR_W/2; // point to left side of target
          const toY = target.y + NODE_H/2;
          // draw a smooth curve (cubic)
          const dx = Math.max(40, (toX - fromX) / 2);
          const pathD = `M ${fromX} ${fromY} C ${fromX + dx} ${fromY} ${toX - dx} ${toY} ${toX} ${toY}`;
          const path = createSvg('path', {d: pathD, class:'arrow'});
          content.appendChild(path);
        } else {
          // safety: point to some null position
          const toX = fromX + 80;
          const toY = fromY;
          const pathD = `M ${fromX} ${fromY} L ${toX} ${toY}`;
          const path = createSvg('path', {d: pathD, class:'arrow ghostArrow'});
          content.appendChild(path);
          const nullTxt = createSvg('text', {x: toX + 8, y: toY + 4, class:'emptyMsg'});
          nullTxt.textContent = 'null';
          content.appendChild(nullTxt);
        }
      } else {
        // points to null: draw a dashed line and "null"
        const toX = fromX + 80;
        const toY = fromY;
        const pathD = `M ${fromX} ${fromY} L ${toX} ${toY}`;
        const path = createSvg('path', {d: pathD, class:'arrow ghostArrow'});
        content.appendChild(path);
        const nullTxt = createSvg('text', {x: toX + 8, y: toY + 4, class:'emptyMsg'});
        nullTxt.textContent = 'null';
        content.appendChild(nullTxt);
      }
    });

    status.textContent = `List size: ${list.size}`;
  }

  function createSvg(tag, attrs){
    const el = document.createElementNS('http://www.w3.org/2000/svg', tag);
    for(const k in attrs){
      el.setAttribute(k, attrs[k]);
    }
    return el;
  }

  // Visual effects: highlight search path, flash deletion, etc.
  async function animateSearch(value){
    clearHighlights();
    if(list.size === 0){
      status.textContent = 'List is empty.';
      return;
    }
    let cur = list.head;
    let idx = 0;
    let found = null;
    while(cur){
      const nodeEl = document.getElementById('node-' + cur.id);
      if(nodeEl){
        nodeEl.classList.add('highlight');
        await sleep(350);
      }
      if(same(cur.value, value)){
        found = {node:cur, index: idx};
        if(nodeEl) nodeEl.classList.add('found');
        status.textContent = `Found value at index ${idx}.`;
        break;
      } else {
        if(nodeEl) nodeEl.classList.remove('highlight');
        idx++;
        cur = cur.next;
      }
    }
    if(!found){
      status.textContent = 'Value not found.';
    }
    // leave found highlighted for a short while
    await sleep(900);
    // clear only the transient highlight, keep 'found' green border for a bit shorter, then reset
    document.querySelectorAll('.node.highlight').forEach(n => n.classList.remove('highlight'));
    document.querySelectorAll('.node.found').forEach((el, i) => {
      // fade out the found highlight after a moment
      setTimeout(()=> el.classList.remove('found'), 600 + i*80);
    });
  }

  async function animateInsert(node, atHead){
    render(); // ensure node exists in DOM
    const nodeEl = document.getElementById('node-' + node.id);
    if(nodeEl){
      nodeEl.classList.add('highlight');
      await sleep(700);
      nodeEl.classList.remove('highlight');
    }
    status.textContent = `Inserted "${node.value}" ${atHead ? 'at head' : 'at tail'}. List size: ${list.size}`;
    render();
  }

  async function animateDelete(removed){
    if(!removed) return;
    // render then find the element
    render();
    const el = document.getElementById('node-' + removed.id);
    if(el){
      el.classList.add('deleted');
      status.textContent = `Deleted "${removed.value}".`;
      await sleep(400);
      // physically re-render to remove it
      render();
    } else {
      status.textContent = `Deleted "${removed.value}".`;
      render();
    }
  }

  function clearHighlights(){
    document.querySelectorAll('.node.highlight').forEach(n => n.classList.remove('highlight'));
    document.querySelectorAll('.node.found').forEach(n => n.classList.remove('found'));
  }

  function sleep(ms){ return new Promise(res => setTimeout(res, ms)); }

  // Button handlers
  insertHeadBtn.addEventListener('click', async () => {
    const v = valueInput.value.trim();
    if(v === ''){
      status.textContent = 'Please enter a value to insert.';
      return;
    }
    const node = list.insertHead(parseValue(v));
    await animateInsert(node, true);
  });

  insertTailBtn.addEventListener('click', async () => {
    const v = valueInput.value.trim();
    if(v === ''){
      status.textContent = 'Please enter a value to insert.';
      return;
    }
    const node = list.insertTail(parseValue(v));
    await animateInsert(node, false);
  });

  deleteBtn.addEventListener('click', async () => {
    const v = delInput.value.trim();
    if(v === ''){
      status.textContent = 'Please enter a value to delete.';
      return;
    }
    const removed = list.deleteByValue(parseValue(v));
    if(!removed){
      status.textContent = 'Value not found; nothing deleted.';
      render();
      return;
    }
    await animateDelete(removed);
  });

  searchBtn.addEventListener('click', async () => {
    const v = searchInput.value.trim();
    if(v === ''){
      status.textContent = 'Please enter a value to search.';
      return;
    }
    await animateSearch(parseValue(v));
  });

  clearBtn.addEventListener('click', () => {
    list.clear();
    render();
    status.textContent = 'Cleared list.';
  });

  // helper parse input to number if numeric
  function parseValue(s){
    if(s.trim() === '') return s;
    if(!isNaN(s) && s.trim() !== '') {
      // keep numeric format but allow leading zeros to remain string? We'll convert to number
      return Number(s);
    }
    return s;
  }

  // initial demo content
  (function seed(){
    list.insertTail(10);
    list.insertTail(20);
    list.insertTail(30);
    render();
    status.textContent = 'Demo list created. Try operations.';
  })();

  // make the svg viewBox width adjust based on nodes to avoid cramped layout
  const observer = new MutationObserver(() => {
    // compute width needed
    const nodes = list.toArray();
    const w = Math.max(400, START_X + (nodes.length) * (NODE_W + GAP) + 160);
    svg.setAttribute('viewBox', `0 0 ${w} 220`);
  });
  observer.observe(content, {childList:true, subtree:true});

  // keyboard Enter handling
  valueInput.addEventListener('keydown', (e)=>{ if(e.key === 'Enter') insertTailBtn.click(); });
  delInput.addEventListener('keydown', (e)=>{ if(e.key === 'Enter') deleteBtn.click(); });
  searchInput.addEventListener('keydown', (e)=>{ if(e.key === 'Enter') searchBtn.click(); });

})();
</script>

</body>
</html>

Here's a single self-contained HTML file that visualizes binary search on a sorted array. Save it as something like "binary_search_visual.html" and open it in a browser. The page shows the array as numbered boxes, an input for the target, and controls: "Step" to advance one iteration, "Auto" to run automatically, "Reset" to restart with a new array, and "Shuffle" to generate a new sorted array. Each step highlights the current search range (light blue), the middle element (orange), and if found it turns green; if the search completes without finding the target, a red message appears.

