<body>
  <div class="card" role="main">
    <h1>Binary Search Visualizer</h1>
    <p class="lead">Enter a target value and step through binary search on a sorted array. The current search range is highlighted, the middle element is marked, and results are shown when it's found or when the search finishes.</p>

    <div class="controls top-row">
      <label>
        Target:
        <input id="targetInput" type="number" value="23" />
      </label>

      <button id="stepBtn">Step</button>
      <button id="autoBtn" class="secondary">Auto</button>
      <button id="resetBtn" class="secondary">Reset</button>
      <button id="shuffleBtn" class="secondary">Shuffle</button>

      <label style="margin-left:auto;">
        Array size:
        <input id="sizeInput" type="number" min="5" max="40" value="13" style="width:78px; padding:6px 8px; border-radius:8px; background:#071a30; color:var(--text); border:1px solid rgba(255,255,255,0.06);" />
      </label>
    </div>

    <div class="array-wrap">
      <div id="array" class="array" aria-live="polite" aria-label="Array elements"></div>
    </div>

    <div class="legend">
      <span><i class="sw range"></i> Current search range</span>
      <span><i class="sw mid"></i> Middle element</span>
      <span><i class="sw found"></i> Found</span>
      <span><i class="sw notfound"></i> Not found</span>
    </div>

    <div class="status" id="status">Ready. Enter a target and press Step or Auto.</div>

    <div class="footer">
      <div class="small info" id="stats">low: — &nbsp; mid: — &nbsp; high: — &nbsp; steps: 0</div>
      <div class="small">Tip: You can change array size, shuffle to create a new sorted array, or reset to start the search over.</div>
    </div>
  </div>

<script>
(function(){
  // Utilities
  function randInt(a,b){return Math.floor(Math.random()*(b-a+1))+a;}
  function clamp(v,a,b){return Math.max(a, Math.min(b, v));}

  // DOM
  const arrayEl = document.getElementById('array');
  const targetInput = document.getElementById('targetInput');
  const stepBtn = document.getElementById('stepBtn');
  const autoBtn = document.getElementById('autoBtn');
  const resetBtn = document.getElementById('resetBtn');
  const shuffleBtn = document.getElementById('shuffleBtn');
  const sizeInput = document.getElementById('sizeInput');
  const statusEl = document.getElementById('status');
  const statsEl = document.getElementById('stats');

  // State
  let arr = [];
  let low = 0, high = -1, mid = -1;
  let steps = 0;
  let running = false;
  let autoTimer = null;
  let finished = false;

  function generateSortedArray(n){
    // Generate sorted unique-ish numbers
    const start = randInt(0,6);
    const a = [];
    let val = start;
    for(let i=0;i<n;i++){
      val += randInt(1,6);
      a.push(val);
    }
    return a;
  }

  function renderArray(){
    arrayEl.innerHTML = '';
    arr.forEach((v,i)=>{
      const cell = document.createElement('div');
      cell.className = 'cell';
      cell.setAttribute('data-idx', i);
      const idxSpan = document.createElement('div');
      idxSpan.className = 'idx';
      idxSpan.textContent = i;
      cell.appendChild(idxSpan);
      const val = document.createElement('div');
      val.textContent = v;
      cell.appendChild(val);

      // apply classes
      if(low<=i && i<=high && !finished) cell.classList.add('range');
      if(i===mid && !finished) cell.classList.add('mid');
      if(finished && i===mid && arr[i] === Number(targetInput.value) && mid>=0 && mid < arr.length) cell.classList.add('found');
      if(finished && !(low<=i && i<=high) && arr[i] !== Number(targetInput.value) && i===mid && mid>=0 && mid < arr.length) {
        // no-op; handled above
      }
      arrayEl.appendChild(cell);
    });
    updateStats();
  }

  function updateStats(){
    statsEl.textContent = `low: ${low>=0?low:'—'}  mid: ${mid>=0?mid:'—'}  high: ${high>=0?high:'—'}  steps: ${steps}`;
  }

  function setStatus(msg, tone){
    statusEl.textContent = msg;
    if(tone==='ok') statusEl.style.color = '';
    else if(tone==='warn') statusEl.style.color = 'var(--muted)';
    else if(tone==='err') statusEl.style.color = 'var(--notfound)';
    else statusEl.style.color = '';
  }

  function startSearch(){
    steps = 0;
    low = 0;
    high = arr.length - 1;
    mid = -1;
    finished = false;
    renderArray();
    setStatus('Search started. Press Step to iterate or Auto to run.', 'warn');
  }

  function step(){
    if(finished) return;
    if(low>high){
      finished = true;
      mid = -1;
      renderArray();
      setStatus(`Not found. Target ${targetInput.value} is not in the array.`, 'err');
      return;
    }
    mid = Math.floor((low + high) / 2);
    steps++;
    renderArray();

    const target = Number(targetInput.value);
    if(arr[mid] === target){
      finished = true;
      renderArray();
      // highlight found cell
      const cell = arrayEl.querySelector(`.cell[data-idx="${mid}"]`);
      if(cell){ cell.classList.remove('mid'); cell.classList.add('found'); }
      setStatus(`Found target ${target} at index ${mid} in ${steps} step${steps===1?'':'s'}.`, 'ok');
      stopAuto();
      return;
    } else if (arr[mid] < target){
      setStatus(`Step ${steps}: arr[${mid}] = ${arr[mid]} < ${target} → move low to ${mid + 1}`, 'warn');
      low = mid + 1;
    } else {
      setStatus(`Step ${steps}: arr[${mid}] = ${arr[mid]} > ${target} → move high to ${mid - 1}`, 'warn');
      high = mid - 1;
    }

    // if next step will be impossible, handle not found on next call
    if(low>high){
      // show the empty range briefly
      renderArray();
    }
  }

  function stopAuto(){
    running = false;
    autoBtn.textContent = 'Auto';
    if(autoTimer){ clearInterval(autoTimer); autoTimer = null; }
  }

  function runAuto(){
    if(running){
      stopAuto();
      return;
    }
    if(finished){
      setStatus('Search already finished. Reset to start again.', 'warn');
      return;
    }
    running = true;
    autoBtn.textContent = 'Stop';
    autoTimer = setInterval(()=>{
      if(finished) { stopAuto(); return; }
      // if no progress possible, do a final call
      if(low>high){ step(); stopAuto(); return; }
      step();
      if(finished) stopAuto();
    }, 700);
  }

  function reset(){
    stopAuto();
    startSearch();
  }

  function shuffle(){
    stopAuto();
    const n = clamp(Number(sizeInput.value) || 13, 5, 40);
    arr = generateSortedArray(n);
    // adjust target default to a value likely present or not
    targetInput.value = arr[Math.floor(arr.length/2)];
    startSearch();
  }

  // initialize
  shuffle();

  // events
  stepBtn.addEventListener('click', ()=>{
    stopAuto();
    if(finished){
      setStatus('Search finished. Reset to start again or Shuffle to create a new array.', 'warn');
      return;
    }
    if(low>high){
      // call step will mark not found
      step();
      return;
    }
    step();
  });

  autoBtn.addEventListener('click', ()=>{
    runAuto();
  });

  resetBtn.addEventListener('click', ()=>{
    targetInput.value = '';
    stopAuto();
    startSearch();
  });

  shuffleBtn.addEventListener('click', ()=>{
    shuffle();
  });

  sizeInput.addEventListener('change', ()=>{
    const v = clamp(Number(sizeInput.value) || 13, 5, 40);
    sizeInput.value = v;
  });

  targetInput.addEventListener('keydown', (e)=>{
    if(e.key === 'Enter'){
      stopAuto();
      startSearch();
      // optional: step immediately
      step();
    }
  });

  // Click on a cell to set target quickly
  arrayEl.addEventListener('click', (e)=>{
    const cell = e.target.closest('.cell');
    if(!cell) return;
    const idx = Number(cell.getAttribute('data-idx'));
    if(Number.isFinite(idx)){
      targetInput.value = arr[idx];
    }
  });

  // accessibility: focus styles with keyboard
  document.addEventListener('keydown', (e)=>{
    if(e.key === 's' && (e.ctrlKey || e.metaKey)) { // Ctrl/Cmd+S to step
      e.preventDefault();
      stepBtn.click();
    }
  });

})();
</script>
</body>
</html>
