      return document.querySelector('input[name="mode"]:checked').value;
    }

    function escapeHtml(s) {
      return String(s)
        .replaceAll('&', '&amp;')
        .replaceAll('<', '&lt;')
        .replaceAll('>', '&gt;')
        .replaceAll('"', '&quot;')
        .replaceAll("'", '&#39;');
    }

    runBtn.addEventListener('click', () => {
      const term = searchInput.value;
      const mode = getMode();
      resultsDiv.innerHTML = '';
      constructedPre.textContent = '';
      filterDescPre.textContent = '';

      // Illustrative "vulnerable-style" constructed query string (DOES NOT EXECUTE SQL)
      // We show how someone might naively build a WHERE clause by concatenation.
      const constructedWhere = `WHERE name LIKE '%${term}%'`;
      const constructedFull = `SELECT * FROM products ${constructedWhere};`;
      constructedPre.textContent = constructedFull;

      // Safe parameterized-style filter description
      const paramPlaceholder = '(:searchTerm)';
      const paramQuery = `SELECT * FROM products WHERE name LIKE '%${paramPlaceholder}%';`;
      const usedParameters = { searchTerm: term };
      filterDescPre.textContent = paramQuery + "\\nParameters: " + JSON.stringify(usedParameters);

      // Now perform actual filtering in JavaScript using two styles:
      // 1) Vulnerable-style (illustration): emulate the effect of treating input as raw text in a naive string-match
      //    For safety we will NOT evaluate or parse the constructed string. Instead we emulate the likely intended effect:
      //    match if the product name includes the raw term text.
      const vulnerableMatches = PRODUCTS.filter(p => p.name.toLowerCase().includes(String(term).toLowerCase()));

      // 2) Safe parameterized-style: treat the search term strictly as data and apply normalization/escaping where appropriate.
      //    Conceptually it's the same filter here, but we also demonstrate additional safe handling (trimming, limiting length).
      const safeInput = String(term).slice(0, 100).trim(); // treat as a bounded parameter (example safety)
      const safeMatches = PRODUCTS.filter(p => p.name.toLowerCase().includes(safeInput.toLowerCase()));

      // Display results side-by-side explanation
      const createList = (arr) => {
        if (arr.length === 0) return '<div class="muted">No results</div>';
        return '<table><thead><tr><th>ID</th><th>Name</th><th>Category</th><th>Price</th></tr></thead><tbody>' +
          arr.map(p => `<tr><td>${p.id}</td><td>${escapeHtml(p.name)}</td><td>${escapeHtml(p.category)}</td><td>$${p.price}</td></tr>`).join('') +
          '</tbody></table>';
      };

      // If we detect characters that look like they might be an attempt to change query structure (quotes, semicolons),
      // we highlight that such characters are untrusted and must be handled on servers. We will not show exploit examples.
      const suspicious = /['";]/.test(term);

      resultsDiv.innerHTML = `
        <div style="display:flex;gap:12px;">
          <div style="flex:1">
            <div style="font-weight:700">Vulnerable-style (illustration)</div>
            <div style="font-size:13px; color:#555; margin-bottom:6px;">Constructed string shown above. For safety we do not parse/execute it here.</div>
            ${createList(vulnerableMatches)}
            ${suspicious ? '<div class="warning" style="margin-top:8px;">Untrusted input contains characters that could alter a query if embedded directly into SQL. Server-side code must not concatenate raw input into queries.</div>' : ''}
          </div>
          <div style="flex:1">
            <div style="font-weight:700">Safe (parameterized-style)</div>
            <div style="font-size:13px; color:#555; margin-bottom:6px;">Input is treated as parameter data; filter applied only as content, never as query structure.</div>
            ${createList(safeMatches)}
            <div class="good" style="margin-top:8px;">Safe handling examples: trim input, limit length, use parameter binding on the server.</div>
          </div>
        </div>
      `;
    });

    resetBtn.addEventListener('click', () => {
      searchInput.value = 'phone';
      constructedPre.textContent = '-- run a search to see constructed string --';
      filterDescPre.textContent = '-- run a search to see parameter values --';
      resultsDiv.innerHTML = '';
    });

    // Run initial search
    runBtn.click();
  </script>
</body>
</html>

