  <section class="panel" id="panel-bubble">
    <h2>Bubble Sort</h2>
    <div class="viz" id="viz-bubble" aria-hidden="true"></div>
    <div class="info">
      <div class="stat">Comparisons: <span id="cmp-bubble">0</span></div>
      <div class="stat">Swaps: <span id="swap-bubble">0</span></div>
      <div class="stat">Pass: <span id="pass-bubble">0</span></div>
      <div class="stat">Status: <span id="state-bubble">idle</span></div>
    </div>
    <div class="explain" id="explain-bubble">
      Average: O(n^2). Best: O(n). Worst: O(n^2). Simple but inefficient on large arrays.
    </div>
  </section>

  <section class="panel" id="panel-insert">
    <h2>Insertion Sort</h2>
    <div class="viz" id="viz-insert" aria-hidden="true"></div>
    <div class="info">
      <div class="stat">Comparisons: <span id="cmp-insert">0</span></div>
      <div class="stat">Swaps (moves): <span id="swap-insert">0</span></div>
      <div class="stat">Index: <span id="idx-insert">0</span></div>
      <div class="stat">Status: <span id="state-insert">idle</span></div>
    </div>
    <div class="explain" id="explain-insert">
      Average: O(n^2). Best: O(n). Worst: O(n^2). Good for small or nearly-sorted arrays.
    </div>
  </section>

  <section class="panel" id="panel-quick">
    <h2>Quick Sort (Lomuto)</h2>
    <div class="viz" id="viz-quick" aria-hidden="true"></div>
    <div class="info">
      <div class="stat">Comparisons: <span id="cmp-quick">0</span></div>
      <div class="stat">Swaps: <span id="swap-quick">0</span></div>
      <div class="stat">Stack depth: <span id="stack-quick">0</span></div>
      <div class="stat">Status: <span id="state-quick">idle</span></div>
    </div>
    <div class="explain" id="explain-quick">
      Average: O(n log n). Best: O(n log n). Worst: O(n^2) (rare with random pivot). Fast for most inputs.
    </div>
  </section>
</main>

<footer>
  Tips: Use smaller sizes to step faster. Counts show actual comparisons and swaps performed by each algorithm.
</footer>

<script>
(() => {
  // Utilities
  function randArray(n){
    const a = [];
    for(let i=0;i<n;i++) a.push(Math.floor(Math.random()*100)+1);
    return a;
  }
  // DOM refs
  const sizeEl = document.getElementById('size');
  const speedEl = document.getElementById('speed');
  const startBtn = document.getElementById('start');
  const pauseBtn = document.getElementById('pause');
  const resetBtn = document.getElementById('reset');

  const vizBubble = document.getElementById('viz-bubble');
  const vizInsert = document.getElementById('viz-insert');
  const vizQuick = document.getElementById('viz-quick');

  // counters and states
  const counters = {
    bubble: {cmp:0, swap:0, pass:0, state:'idle'},
    insert: {cmp:0, swap:0, idx:0, state:'idle'},
    quick: {cmp:0, swap:0, stack:0, state:'idle'}
  };

  // state
  let baseArray = randArray(parseInt(sizeEl.value,10));
  let paused = true;
  let speed = parseInt(speedEl.value,10); // 1..200 higher => faster
  let animId = null;

  // visual helpers
  function renderViz(container, arr, highlights={}){
    // highlights: {compare:[i,j], swap:[i,j], pivot:i}
    container.innerHTML = '';
    const n = arr.length;
    const max = Math.max(...arr);
    for(let i=0;i<n;i++){
      const v = arr[i];
      const bar = document.createElement('div');
      bar.className = 'bar';
      if(n>60) bar.classList.add('small');
      let h = (v / max) * 100;
      bar.style.height = h + '%';
      bar.textContent = n<=40 ? String(v) : '';
      if(highlights.compare && highlights.compare.includes(i)) bar.classList.add('compare');
      if(highlights.swap && highlights.swap.includes(i)) bar.classList.add('swap');
      if(typeof highlights.pivot === 'number' && highlights.pivot===i){
        bar.style.boxShadow = 'inset 0 -8px 30px rgba(255,255,255,0.05), 0 0 12px rgba(255,255,255,0.02)';
        bar.style.outline = '2px solid rgba(99,102,241,0.12)';
      }
      container.appendChild(bar);
    }
  }

  // initial render
  function setAllArrays(arr){
    renderViz(vizBubble, arr);
    renderViz(vizInsert, arr);
    renderViz(vizQuick, arr);
  }
  setAllArrays(baseArray);

  // algorithm generators produce a sequence of steps for animation
  // Each step: {type:'compare'|'swap'|'set'|'pass'|'done'|'pivot', indices:[], arr:copy }
  // We will supply array copies to keep visual panels consistent.

  function* bubbleSortGen(arr){
    const a = arr.slice();
    const n = a.length;
    let swapped;
    for(let pass=0; pass<n-1; pass++){
      swapped = false;
      yield {type:'pass', pass:pass+1, arr:a.slice()};
      for(let i=0;i<n-1-pass;i++){
        yield {type:'compare', indices:[i,i+1], arr:a.slice()};
        if(a[i] > a[i+1]){
          // swap
          [a[i], a[i+1]] = [a[i+1], a[i]];
          swapped = true;
          yield {type:'swap', indices:[i,i+1], arr:a.slice()};
        }
      }
      if(!swapped) break;
    }
    yield {type:'done', arr:a.slice()};
  }

  function* insertionSortGen(arr){
    const a = arr.slice();
    const n = a.length;
    for(let i=1;i<n;i++){
      let key = a[i];
      let j = i-1;
      yield {type:'index', index:i, arr:a.slice()};
      while(j>=0){
        yield {type:'compare', indices:[j,i], arr:a.slice()};
        if(a[j] > key){
          a[j+1] = a[j];
          yield {type:'move', indices:[j,j+1], arr:a.slice()};
          j--;
        }else break;
      }
      a[j+1] = key;
      yield {type:'insert', index:j+1, arr:a.slice()};
    }
    yield {type:'done', arr:a.slice()};
  }

  // Quick sort using Lomuto partition but iterative to emit steps
  function* quickSortGen(arr){
    const a = arr.slice();
    const stack = [{lo:0, hi:a.length-1}];
    while(stack.length){
      const {lo, hi} = stack.pop();
      if(lo>=hi) continue;
      yield {type:'stack', depth: stack.length+1, arr:a.slice()};
      // partition Lomuto
      const pivot = a[hi];
      let i = lo;
      yield {type:'pivot', pivotIndex:hi, arr:a.slice()};
      for(let j=lo;j<hi;j++){
        yield {type:'compare', indices:[j,hi], arr:a.slice()};
        if(a[j] < pivot){
          if(i!==j){
            [a[i], a[j]] = [a[j], a[i]];
            yield {type:'swap', indices:[i,j], arr:a.slice()};
          }
          i++;
        }
      }
      // place pivot
      if(i!==hi){
        [a[i], a[hi]] = [a[hi], a[i]];
        yield {type:'swap', indices:[i,hi], arr:a.slice()};
      }
      // push right and left
      // push larger segment first to keep stack smaller (optional)
      if(i+1<hi) stack.push({lo:i+1, hi:hi});
      if(lo<i-1) stack.push({lo:lo, hi:i-1});
    }
    yield {type:'done', arr:a.slice()};
  }

  // control and step execution
  let gens = null;
  function resetGenerators(){
    const arr = baseArray.slice();
    gens = {
      bubble: bubbleSortGen(arr),
      insert: insertionSortGen(arr),
      quick: quickSortGen(arr)
    };
    // reset counters and UI
    counters.bubble = {cmp:0, swap:0, pass:0, state:'ready'};
    counters.insert = {cmp:0, swap:0, idx:0, state:'ready'};
    counters.quick = {cmp:0, swap:0, stack:0, state:'ready'};
    updateAllCounters();
    setAllArrays(baseArray);
    document.getElementById('state-bubble').textContent = 'ready';
    document.getElementById('state-insert').textContent = 'ready';
    document.getElementById('state-quick').textContent = 'ready';
  }

  function updateAllCounters(){
    document.getElementById('cmp-bubble').textContent = counters.bubble.cmp;
    document.getElementById('swap-bubble').textContent = counters.bubble.swap;
    document.getElementById('pass-bubble').textContent = counters.bubble.pass;
    document.getElementById('cmp-insert').textContent = counters.insert.cmp;
    document.getElementById('swap-insert').textContent = counters.insert.swap;
    document.getElementById('idx-insert').textContent = counters.insert.idx;
    document.getElementById('cmp-quick').textContent = counters.quick.cmp;
    document.getElementById('swap-quick').textContent = counters.quick.swap;
    document.getElementById('stack-quick').textContent = counters.quick.stack;
  }

  // step each generator once and update visuals
  function stepAll(){
    if(!gens) return;
    // bubble
    const b = gens.bubble.next();
    if(!b.done){
      const s = b.value;
      handleBubbleStep(s);
    } else {
      document.getElementById('state-bubble').textContent = 'finished';
    }
    // insert
    const ins = gens.insert.next();
    if(!ins.done){
      handleInsertStep(ins.value);
    } else {
      document.getElementById('state-insert').textContent = 'finished';
    }
    // quick
    const q = gens.quick.next();
    if(!q.done){
      handleQuickStep(q.value);
    } else {
      document.getElementById('state-quick').textContent = 'finished';
    }
    updateAllCounters();
  }

  function handleBubbleStep(s){
    if(s.type==='pass'){
      counters.bubble.pass = s.pass;
      counters.bubble.state = 'pass';
      document.getElementById('state-bubble').textContent = 'pass '+s.pass;
      renderViz(vizBubble, s.arr);
    } else if(s.type==='compare'){
      counters.bubble.cmp++;
      counters.bubble.state = 'compare';
      document.getElementById('state-bubble').textContent = 'comparing';
      renderViz(vizBubble, s.arr, {compare:s.indices});
    } else if(s.type==='swap'){
      counters.bubble.swap++;
      counters.bubble.state = 'swap';
      document.getElementById('state-bubble').textContent = 'swapping';
      renderViz(vizBubble, s.arr, {swap:s.indices});
    } else if(s.type==='done'){
      counters.bubble.state = 'done';
      document.getElementById('state-bubble').textContent = 'done';
      renderViz(vizBubble, s.arr);
    }
  }

  function handleInsertStep(s){
    if(s.type==='index'){
      counters.insert.idx = s.index;
      counters.insert.state = 'index';
      document.getElementById('state-insert').textContent = 'scanning';
      renderViz(vizInsert, s.arr, {compare:[s.index]});
    } else if(s.type==='compare'){
      counters.insert.cmp++;
      counters.insert.state = 'compare';
      document.getElementById('state-insert').textContent = 'comparing';
      renderViz(vizInsert, s.arr, {compare:s.indices});
    } else if(s.type==='move'){
      counters.insert.swap++;
      counters.insert.state = 'move';
      document.getElementById('state-insert').textContent = 'moving';
      renderViz(vizInsert, s.arr, {swap:s.indices});
    } else if(s.type==='insert'){
      counters.insert.state = 'insert';
      document.getElementById('state-insert').textContent = 'inserting';
      renderViz(vizInsert, s.arr);
    } else if(s.type==='done'){
      counters.insert.state = 'done';
      document.getElementById('state-insert').textContent = 'done';
      renderViz(vizInsert, s.arr);
    }
  }

  function handleQuickStep(s){
    if(s.type==='stack'){
      counters.quick.stack = s.depth;
      counters.quick.state = 'stack';
      document.getElementById('state-quick').textContent = 'partitioning';
      renderViz(vizQuick, s.arr);
    } else if(s.type==='pivot'){
      counters.quick.state = 'pivot';
      document.getElementById('state-quick').textContent = 'pivot';
      renderViz(vizQuick, s.arr, {pivot:s.pivotIndex});
    } else if(s.type==='compare'){
      counters.quick.cmp++;
      counters.quick.state = 'compare';
      document.getElementById('state-quick').textContent = 'comparing';
      renderViz(vizQuick, s.arr, {compare:s.indices, pivot: s.pivotIndex});
    } else if(s.type==='swap'){
      counters.quick.swap++;
      counters.quick.state = 'swap';
      document.getElementById('state-quick').textContent = 'swapping';
      renderViz(vizQuick, s.arr, {swap:s.indices});
    } else if(s.type==='done'){
      counters.quick.state = 'done';
      document.getElementById('state-quick').textContent = 'done';
      renderViz(vizQuick, s.arr);
    }
  }

  // animation loop
  function animate(){
    if(paused) return;
    // speed mapping: speed slider higher -> smaller delay
    const sp = parseInt(speedEl.value,10);
    const delay = Math.max(3, 220 - sp); // ms per step
    stepAll();
    // check finished: if all states are 'done' then pause
    const allDone = (document.getElementById('state-bubble').textContent==='done')
                 && (document.getElementById('state-insert').textContent==='done')
                 && (document.getElementById('state-quick').textContent==='done');
    if(allDone){
      paused = true;
      return;
    }
    animId = setTimeout(animate, delay);
  }

  // wire buttons
  startBtn.addEventListener('click', ()=>{
    if(!gens) resetGenerators();
    if(paused){
      paused = false;
      animate();
    }
  });
  pauseBtn.addEventListener('click', ()=>{
    paused = true;
    if(animId) { clearTimeout(animId); animId = null; }
  });
  resetBtn.addEventListener('click', ()=>{
    paused = true;
    if(animId) { clearTimeout(animId); animId = null; }
    // generate new base array
    baseArray = randArray(parseInt(sizeEl.value,10));
    resetGenerators();
  });

  // update speed or size
  speedEl.addEventListener('input', ()=>{ /* speed used in animate */ });
  sizeEl.addEventListener('input', ()=>{
    baseArray = randArray(parseInt(sizeEl.value,10));
    paused = true;
    if(animId) { clearTimeout(animId); animId = null; }
    resetGenerators();
  });

  // initialize
  resetGenerators();

})();
</script>
