<body>
  <h1>Sorting comparison: Bubble sort vs Insertion sort vs Quick sort</h1>

  <div class="top">
    <div class="controls" title="Adjust size and speed">
      <label class="small">Array size <span id="sizeLabel">40</span></label>
      <input id="size" type="range" min="10" max="160" value="40">
      <label class="small">Speed <span id="speedLabel">60 ms</span></label>
