      // Tokenize (very naive)
      // We'll split on OR/AND (case-insensitive) into clauses
      const clauses = expr.split(/\bOR\b/i).map(s => s.trim());
      // If multiple OR parts exist, we'll treat as OR across clauses
      const parsedClauses = clauses.map(clause => {
        // Further split AND within clause (we treat AND as higher precedence here)
        const andParts = clause.split(/\bAND\b/i).map(s => s.trim());
        const andParsed = andParts.map(part => {
          // Try to match: field op value
          // op can be =, <, >, <=, >=
          const m = part.match(/^([a-zA-Z_][a-zA-Z0-9_]*)\s*(=|<=|>=|<|>)\s*'(.*)'$/);
          if (m) {
            return { type: 'cmp', field: m[1], op: m[2], value: m[3] };
          }
          const m2 = part.match(/^([a-zA-Z_][a-zA-Z0-9_]*)\s*(=|<=|>=|<|>)\s*([0-9.]+)$/);
          if (m2) {
            return { type: 'cmp', field: m2[1], op: m2[2], value: Number(m2[3]) };
          }
          // As a safety: if pattern doesn't match, mark as invalid
          return { type: 'invalid', raw: part };
        });
        return { type: 'and', parts: andParsed };
      });
      return { type: 'or', clauses: parsedClauses };
    }

    function evalParsed(parsed, row) {
      if (parsed.type !== 'or') return false;
      for (const clause of parsed.clauses) {
        // each clause is an AND of parts
        let andOk = true;
        for (const part of clause.parts) {
          if (part.type === 'invalid') { andOk = false; break; }
          const v = row[part.field];
          const rv = part.value;
          switch (part.op) {
            case '=':
              // Loose comparison with string/number handling
              if (typeof v === 'number') {
                andOk = (Number(rv) === v);
              } else {
                andOk = (String(v) === String(rv));
              }
              break;
            case '<':
              andOk = Number(v) < Number(rv); break;
            case '>':
              andOk = Number(v) > Number(rv); break;
            case '<=':
              andOk = Number(v) <= Number(rv); break;
            case '>=':
              andOk = Number(v) >= Number(rv); break;
            default:
              andOk = false;
          }
          if (!andOk) break;
        }
        if (andOk) return true;
      }
      return false;
    }

    function runQueryVulnerable(userInput) {
      // Simulate building a query string via concatenation (vulnerable style)
      // e.g. "SELECT * FROM products WHERE " + userInput
