        resultsBody.appendChild(tr);
      }
    }

    function escapeHtml(s) {
      return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
    }

    // Vulnerable simulation: we build a "where expression" string by concatenating user input.
    // Then we "evaluate" that expression with a very small parser that is fooled if user input contains operators.
    function vulnerableFilter(field, userInput) {
