      // We'll show the raw expression to the user
      queryBox.textContent = '[VULNERABLE] expression string:\n' + rawExpr + '\n\n(this string would normally be sent to a database/engine)';
      // Very small evaluator: interpret expressions of the form product.field == "value"
      // But because userInput could itself contain ' OR ' or other syntax, we split and try to emulate how naive text allows logic.
      // For demonstration only: parse OR / AND tokens at top level if present.
      try {
        // Naive "evaluation": support OR and AND with equalities.
        const tokens = rawExpr.split(/\s+(OR|AND)\s+/i);
        // tokens like ['product.name == "Widget', 'OR', 'product.name == "1"="1"']
        // Evaluate left-to-right
