        for (let i = 1; i < tokens.length; i += 2) {
          const op = tokens[i].toUpperCase();
          const right = evalEquality(tokens[i+1]);
          if (op === 'OR') acc = acc || right;
          else acc = acc && right;
        }
        // If acc is a boolean, we use it for all products (because user injected logic not tied to product context),
        // else fall back to per-product equality (normal case)
        if (typeof acc === 'boolean') {
          // If it's true, return all products; false -> none.
          return acc ? products.slice() : [];
        }
      } catch (e) {
        // parsing failed; fall back to safe per-product check
      }

      // Normal per-product equality: compare string representation
      return products.filter(p => {
        const fieldVal = String(p[field]);
        return fieldVal === String(userInput);
      });

      function evalEquality(expr) {
        // Very naive: expecting something like 'product.name == "value"' or 'product.price == "10"'
        // If the expr contains both sides, evaluate to boolean.
        const m = expr.match(/product\.([a-zA-Z_]+)\s*==\s*"(.*)"\s*$/);
        if (!m) {
          // Try to detect if the expression is like '"1"="1"' (injected equality)
          const m2 = expr.match(/^\s*"(.*)"\s*==\s*"(.*)"\s*$/);
          if (m2) {
            return m2[1] === m2[2];
          }
          throw new Error('unsupported expr: ' + expr);
        }
        const fieldName = m[1];
        const value = m[2];
        // If the value itself contains a pattern like '"1"="1"', detect and evaluate that equality to boolean.
        const inner = value.match(/^\s*"(.*)"\s*==\s*"(.*)"\s*$/);
        if (inner) {
          return inner[1] === inner[2];
        }
        // Otherwise, this is a per-product check — return a function-like placeholder that will be resolved later.
        // But for our simple top-level eval, we return false so top-level doesn't short-circuit incorrectly.
        return false;
      }
    }

    // Safe/parameterized simulation: we treat user input as a bound value and never interpret it as part of the expression.
    function safeFilter(field, userInput) {
      // Build a "parameterized" expression string visible to user
      const expr = 'SELECT * WHERE product.' + field + ' == ?';
      queryBox.textContent = '[SAFE] parameterized expression:\n' + expr + '\n\nbound parameter: ' + JSON.stringify(userInput);
      // Evaluate by strict comparison of field to input. Input never changes the structure.
      return products.filter(p => {
        // Try numeric match for price if the field is price and input is numeric
        if (field === 'price') {
          const n = Number(userInput);
          if (!Number.isNaN(n)) return p.price === n;
          // else treat as string-to-string (no coercion)
          return String(p.price) === String(userInput);
        }
        return String(p[field]) === String(userInput);
      });
    }

    function run() {
      const mode = modeEl.value;
      const field = fieldEl.value;
      const userInput = inputEl.value;
