<script>
// In-memory "products" database
const products = [
  { id: 1, name: "Smartphone", category: "Electronics", price: 699 },
  { id: 2, name: "Laptop", category: "Computers", price: 1299 },
  { id: 3, name: "Notebook (paper)", category: "Stationery", price: 3.5 },
  { id: 4, name: "Phone Case", category: "Accessories", price: 19 },
  { id: 5, name: "Cookbook", category: "Books", price: 25 },
  { id: 6, name: "Bluetooth Headphones", category: "Electronics", price: 149 },
  { id: 7, name: "Desk Lamp", category: "Furniture", price: 42 },
  { id: 8, name: "Phone Charger", category: "Accessories", price: 29 }
];

// Utility: render results
function renderList(container, list) {
  container.innerHTML = '';
  if (list.length === 0) {
    container.textContent = '(no results)';
    return;
  }
  for (const p of list) {
    const el = document.createElement('div');
    el.className = 'product';
    el.innerHTML = `<strong>${escapeHtml(p.name)}</strong> — ${escapeHtml(p.category)} — $${p.price}`;
    container.appendChild(el);
  }
}

function escapeHtml(s) {
  return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}

// Very small simulated parser helpers to imitate SQL-like behavior
// Note: this is a simulation for demonstration only.

// Evaluate a simple expression against a product.
// Supported expressions in the vulnerable simulation:
// - name LIKE "%text%"  (supports % as wildcard, and quotes)
// - category = "CategoryName"
// - price < number, price > number, price = number
// - raw OR/AND combining of subexpressions with simple tokens
// The vulnerable path will be given a constructed expression string that includes user input directly.
// The safe path will instead build a filter using parameter binding (no parsing of user input as expressions).

// Simple tokenizer (very forgiving)
function tokenize(expr) {
  const tokens = [];
  const re = /\s*(\(|\)|<=|>=|!=|=|<|>|OR\b|AND\b|LIKE\b|--.*$|"(?:[^"\\]|\\.)*"|'(?:[^'\\]|\\.)*'|%|\S+)/ig;
  let m;
  while ((m = re.exec(expr)) !== null) {
    const t = m[1];
    if (t.startsWith('--')) break; // simulate SQL comment: rest ignored
    tokens.push(t);
  }
  return tokens;
}

// Very small expression evaluator that supports a subset of operations.
// This is intentionally minimal and permissive for demonstration.
function evaluateExpressionOnProduct(expr, product) {
  // For safety, limit expression length
  if (expr.length > 2000) return false;
  const tokens = tokenize(expr);
  let i = 0;
  function peek() { return tokens[i]; }
  function consume(tok) { if (peek() === tok) i++; else throw new Error('parse error: expected ' + tok + ' got ' + peek()); }

  // parse primary: supports conditions or parenthesis
  function parsePrimary() {
    const tk = peek();
    if (tk === '(') {
      consume('(');
      const node = parseOr();
      consume(')');
      return node;
    }
    // parse condition: e.g. name LIKE "foo", category = "Books", price < 100
    const left = peek(); i++;
    const op = peek(); i++;
    const right = peek(); i++;
    return { type: 'cond', left, op, right };
  }

  function parseAnd() {
    let left = parsePrimary();
    while (peek() && peek().toUpperCase() === 'AND') {
      i++; // consume AND
      const right = parsePrimary();
      left = { type:'and', left, right };
    }
    return left;
  }

  function parseOr() {
    let left = parseAnd();
    while (peek() && peek().toUpperCase() === 'OR') {
      i++; // consume OR
      const right = parseAnd();
      left = { type:'or', left, right };
    }
    return left;
  }

  const ast = parseOr();

  function evalNode(node) {
    if (!node) return false;
    if (node.type === 'and') return evalNode(node.left) && evalNode(node.right);
    if (node.type === 'or') return evalNode(node.left) || evalNode(node.right);
    if (node.type === 'cond') {
      const left = node.left.toLowerCase();
      const op = node.op.toUpperCase();
      const rawRight = node.right;
      // strip quotes if present
      let right = rawRight;
      if ((right.startsWith('"') && right.endsWith('"')) || (right.startsWith("'") && right.endsWith("'"))) {
        right = right.slice(1, -1).replace(/\\(["'])/g,'$1');
      }
      if (left === 'name' || left === 'category') {
        const field = product[left];
        if (op === 'LIKE') {
          // treat % as wildcard
          const pattern = '^' + right.split('%').map(escapeRegExp).join('.*') + '$';
          return (new RegExp(pattern, 'i')).test(field);
        } else if (op === '=') {
          return field.toLowerCase() === right.toLowerCase();
        }
      } else if (left === 'price') {
        const val = parseFloat(right);
        if (isNaN(val)) return false;
        if (op === '<') return product.price < val;
        if (op === '>') return product.price > val;
        if (op === '=') return product.price === val;
      }
      return false;
    }
    return false;
  }

  try {
    return evalNode(ast);
  } catch (e) {
    // parse errors -> no match
    return false;
  }
}

function escapeRegExp(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Vulnerable simulation: build a WHERE-like string by concatenating user input directly.
// For this demo, we pretend the app expects users to type a condition that will be appended
// to "WHERE " + userInput. Common unsafe pattern: "SELECT * FROM products WHERE " + userInput
function vulnerableSearch(userInput) {
  // Example of naive concatenation into a WHERE clause:
  const whereClause = `name LIKE "%${userInput}%"`;
  // But to illustrate injections like OR 1=1, we also support if the user includes OR or other keywords
  // For the demo we will pass the entire constructed whereClause to our simulated evaluator
  const constructed = whereClause;
  // Evaluate constructed expression against each product (using the permissive evaluator)
  const results = products.filter(p => evaluateExpressionOnProduct(constructed, p));
  return { constructed, results };
}

// Safe simulation: parameterized binding
// Instead of building an expression that might contain SQL keywords, we bind the input as a value.
// In real SQL you'd use prepared statements like: WHERE name LIKE ?  with param "%userInput%"
function safeSearch(userInput) {
  // Parameter binding: we treat the user input purely as a value and escape/transform it as needed.
  // For LIKE behavior we will search for substring matches safely (without parsing the input as SQL).
  // We don't allow the input to add operators like OR 1=1.
  const param = userInput; // bound parameter
  // For demonstration we simulate a parameterized LIKE by checking substring in a case-insensitive way.
  const lowerParam = param.toLowerCase();
  const results = products.filter(p => p.name.toLowerCase().includes(lowerParam));
  // For display, we show pseudocode of the prepared statement and bound parameter
  const prepared = {
    statement: 'SELECT * FROM products WHERE name LIKE ?',
    boundParameter: `%${param}%`
  };
  return { prepared, results };
}

// UI wiring
const searchInput = document.getElementById('search');
const runBtn = document.getElementById('runBtn');
const vulnQuery = document.getElementById('vulnQuery');
const vulnResults = document.getElementById('vulnResults');
const safeQuery = document.getElementById('safeQuery');
const safeResults = document.getElementById('safeResults');

function runSearch() {
  const input = searchInput.value;
  // Vulnerable
  const vuln = vulnerableSearch(input);
  vulnQuery.textContent = vuln.constructed;
  renderList(vulnResults, vuln.results);

  // Safe
  const safe = safeSearch(input);
  safeQuery.textContent = safe.prepared.statement + '\n-- bound parameter: ' + JSON.stringify(safe.prepared.boundParameter);
  renderList(safeResults, safe.results);
}

runBtn.addEventListener('click', runSearch);
searchInput.addEventListener('keydown', (e) => { if (e.key === 'Enter') runSearch(); });

// examples
document.getElementById('example1').addEventListener('click', () => { searchInput.value = 'phone'; runSearch(); });
document.getElementById('example2').addEventListener('click', () => { searchInput.value = 'phone" OR 1=1 --'; runSearch(); });
document.getElementById('example3').addEventListener('click', () => { searchInput.value = '%'; runSearch(); });

// Initial run
runSearch();
</script>

</body>
</html>

Explanation of what's shown and why parameterized queries are safe:
- Vulnerable mode: simulates taking the user's input and inserting it directly into a WHERE-like expression (string concatenation). If a user supplies input such as: phone" OR 1=1 -- the constructed expression may become: name LIKE "%phone" OR 1=1 --%". A parsing/evaluation phase that interprets that expression could treat OR 1=1 as a second condition that makes the WHERE always true, returning all rows. In a real database, this can allow attackers to bypass authentication, extract data, or perform other malicious actions.
- Safe (parameterized) mode: instead of inserting the input into the expression, the application prepares a statement with placeholders and binds the input as a value. Special characters or keywords inside the input are treated as data, not as SQL syntax. That prevents the input from changing the logical structure of the query. In the demo, the safe mode always searches for the literal substring the user provided (case-insensitive) and never parses it as part of a SQL expression.

Best practices summary:
- Never build SQL query strings by concatenating untrusted input.
- Use parameterized queries / prepared statements (most database drivers and ORMs support them).
- Validate and sanitize input according to expected formats (e.g., if you expect a number, verify it's a number).
- Use least privilege for database credentials and limit what injected queries could accomplish.

