Below is a single self-contained HTML file that demonstrates a singleton-style state manager for a theme toggle (light/dark). The page shows multiple elements reacting to the theme. After the file I explain why singletons are often problematic and give better alternatives and when to use them.

Save the following as a .html file and open in a browser.

<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width,initial-scale=1" />
  <title>Theme Toggle - Singleton Example</title>
  <style>
    :root {
      --bg: #ffffff;
      --fg: #111111;
      --card-bg: #f4f4f4;
      --accent: #0066cc;
    }

    .dark {
      --bg: #111317;
      --fg: #e8eef6;
      --card-bg: #1a1f24;
      --accent: #36a3ff;
    }

    html, body {
      height: 100%;
      margin: 0;
      background: var(--bg);
      color: var(--fg);
      font-family: system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial;
      transition: background 220ms ease, color 220ms ease;
    }

    header {
      padding: 1rem;
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 1rem;
    }

    .container {
      max-width: 900px;
      margin: 1rem auto;
      padding: 0 1rem;
    }

    .toggle-btn {
      background: transparent;
      border: 1px solid var(--accent);
      color: var(--accent);
      padding: 0.4rem 0.7rem;
      border-radius: 6px;
      cursor: pointer;
      transition: background 160ms ease, color 160ms ease;
    }
    .toggle-btn:hover { background: rgba(0,0,0,0.04); }

    .grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
      gap: 1rem;
      margin-top: 1rem;
    }

    .card {
      background: var(--card-bg);
      border-radius: 8px;
      padding: 1rem;
      box-shadow: 0 1px 0 rgba(0,0,0,0.04);
      transition: background 220ms ease, color 220ms ease, box-shadow 220ms ease;
    }

    footer {
      margin-top: 2rem;
      padding: 1rem 0;
      color: var(--fg);
      opacity: 0.8;
    }

    .accent {
      color: var(--accent);
    }

  </style>
</head>
<body>
  <header>
    <div>
      <strong>Theme Demo (Singleton State)</strong>
      <div style="font-size:0.9rem; opacity:0.8">Multiple elements listen to a single global store</div>
    </div>
    <div>
      <button id="toggleBtn" class="toggle-btn">Toggle Theme</button>
    </div>
  </header>

  <main class="container">
    <section class="grid">
      <div class="card" id="card1">
        <h3>Card A</h3>
        <p>This card reacts to the shared theme state.</p>
      </div>
      <div class="card" id="card2">
        <h3>Card B</h3>
        <p>Another card using the same singleton store.</p>
      </div>
      <div class="card" id="card3">
        <h3>Card C</h3>
        <p>All elements toggle together.</p>
      </div>
      <div class="card" id="card4">
        <h3>Card D</h3>
        <p>Local elements may also query the store.</p>
      </div>
    </section>

    <footer>
      <div>Current theme: <span id="currentTheme" class="accent">light</span></div>
    </footer>
  </main>

  <script>
    /*
      Simple singleton-style theme store.
      - Single instance exported from an IIFE
      - Keeps theme state and a list of subscribers
      - Exposes methods: get(), toggle(), set(), subscribe(), unsubscribe()
      This is intentionally minimal for demo/educational use.
    */

    const ThemeStore = (function createThemeStore() {
      // private state
      let instance; // ensure only one instance
      function init() {
        let theme = (localStorage.getItem('demo-theme') === 'dark') ? 'dark' : 'light';
        const subscribers = new Set();

        function notify() {
          for (const s of subscribers) {
            try { s(theme); } catch (e) { console.error('subscriber error', e); }
          }
        }

        return {
          get() { return theme; },
          set(newTheme) {
            if (newTheme !== 'light' && newTheme !== 'dark') return;
            if (theme === newTheme) return;
            theme = newTheme;
            localStorage.setItem('demo-theme', theme);
            notify();
          },
          toggle() {
            this.set(theme === 'light' ? 'dark' : 'light');
          },
          subscribe(fn) {
            if (typeof fn !== 'function') return;
            subscribers.add(fn);
            // immediately call to initialize
            try { fn(theme); } catch (e) { console.error('subscriber init error', e); }
            // return unsubscribe helper
            return () => subscribers.delete(fn);
          },
          // for debugging
          _subCount() { return subscribers.size; }
        };
      }

      return {
        getInstance() {
          if (!instance) instance = init();
          return instance;
        }
      };
    })();

    // App wiring
    (function main() {
      const store = ThemeStore.getInstance();

      // Apply theme to <html> element for CSS vars to switch
      function applyTheme(t) {
        const html = document.documentElement;
        if (t === 'dark') html.classList.add('dark'); else html.classList.remove('dark');
        document.getElementById('currentTheme').textContent = t;
        // Update toggle button label for clarity
        const btn = document.getElementById('toggleBtn');
        btn.textContent = t === 'dark' ? 'Switch to Light' : 'Switch to Dark';
      }

      // Subscribe global apply
      store.subscribe(applyTheme);

      // Button toggles the singleton store
      document.getElementById('toggleBtn').addEventListener('click', () => store.toggle());

      // Demonstrate local components subscribing individually
      function mountCard(cardId) {
        const el = document.getElementById(cardId);
        if (!el) return;
        // Each card subscribes to the same singleton store.
        const unsub = store.subscribe(t => {
          el.style.border = t === 'dark' ? '1px solid rgba(255,255,255,0.06)' : '1px solid rgba(0,0,0,0.04)';
          el.querySelector('h3').style.color = t === 'dark' ? '#aee3ff' : '#0056a6';
        });
        // Example of potential cleanup — not used in this demo.
        // return unsub;
      }

      ['card1','card2','card3','card4'].forEach(mountCard);

      // For demonstration: log subscriber count every few seconds
      // (to show there is a central list of subscribers)
      setInterval(() => {
        console.debug('ThemeStore subscribers:', store._subCount());
      }, 60000);
    })();
  </script>
</body>
</html>

Discussion — why singletons are problematic, and alternatives

Problems with singletons
- Global mutable state: Singletons act like global variables. Any part of the code can read and mutate state, which increases implicit coupling and makes reasoning about the flow harder.
- Hidden dependencies: Functions/components can rely on the singleton without declaring it in their interface, making testing, reuse, and maintenance harder.
- Order-of-initialization issues: If different modules expect the singleton to be initialized or configured differently, subtle bugs occur (race conditions, inconsistent state).
- Harder to test: Tests often need to reset, mock or reconfigure the singleton. Because the instance is global, tests may leak state between runs unless explicitly reset.
- Tight coupling and reduced modularity: Code becomes tightly coupled to the singleton’s API and lifecycle, making refactoring and parallel development more difficult.
- Concurrency and scaling issues: In environments where multiple instances/processes are involved (workers, serverless functions, iframes), assuming a single process-wide instance can be wrong.
- Hidden side effects: Mutations can happen anywhere; tracking what changed the singleton at a specific time can be difficult.
- Inversion of control lost: Singletons often centralize control in a way that prevents higher-level orchestration or composition.

When singletons are tempting but better alternatives exist
- Pass dependencies explicitly: Instead of importing a global singleton, pass the needed store (or a facade) into functions/components. This makes dependencies explicit and easier to test.
- Dependency injection (DI): Use a DI container or simple factory functions to provide configured instances to modules/components. This supports multiple instances and easier testing.
- Local state for components: Use component-local state when the state doesn't need to be globally shared. Lot easier to reason about and test.
- Scoped stores: If you need shared state within a part of an app (e.g., a page, a subtree), use a scoped store passed down via props/context rather than a global singleton.
- Immutable state and event streams: Using immutable state updates (Redux-style) or event streams (RxJS) with explicit reducers/handlers reduces surprises and makes time-travel/debugging possible.
- Factories producing instances: Provide factory functions that create stores/clients so callers can decide whether to share an instance or get a fresh one — useful in tests.

When singletons might be acceptable
- Truly global resources where a single OS/hardware resource must be managed (e.g., a unique hardware device connection in a native app), provided the singleton is carefully encapsulated, documented, and testable.
- Application bootstrap with controlled lifecycle: If the application has a clear startup/teardown phase and the singleton is configured there and treated as read-only thereafter, the risks are reduced.
- Small scripts or demos: For tiny apps or throwaway scripts, singletons can be pragmatic.

How to mitigate singleton problems if you must use one
- Keep the singleton thin and well-encapsulated; expose a small, stable API.
- Allow explicit creation/configuration (factory) and expose a way to reset/replace the instance for tests.
- Prefer subscribing to changes (observer pattern) instead of letting many parts write into it directly.
- Document its lifecycle and side effects.
- Use immutable updates and avoid exposing mutating internals.

Concluding short recommendation
Use singletons sparingly. Prefer explicit dependency passing or factories and scoped/shared stores. If you need a central state manager, pick a predictable pattern (Redux-like immutable state, context + provider, or a DI approach) so dependencies and side effects are explicit and testable.

