  </div>

  <div class="grid">
    <div class="panel" id="p-bubble">
      <h3>Bubble Sort <span style="float:right;color:var(--danger)">Playful roast mode</span></h3>
      <div class="canvas"><div class="bars" id="bars-bubble"></div></div>
      <div class="stats">
        <div>Steps: <span id="steps-bubble">0</span></div>
        <div>Swaps: <span id="swaps-bubble">0</span></div>
        <div>Time: <span id="time-bubble">0.000</span>s</div>
      </div>
      <div class="big-o">
        Complexity: Best O(n), Average O(n^2), Worst O(n^2). Why it's slow: repeated adjacent swaps; many passes.
      </div>
    </div>

    <div class="panel" id="p-merge">
      <h3>Merge Sort <span style="float:right;color:var(--good)">Divide & conquer</span></h3>
      <div class="canvas"><div class="bars" id="bars-merge"></div></div>
      <div class="stats">
        <div>Steps: <span id="steps-merge">0</span></div>
        <div>Array accesses: <span id="swaps-merge">0</span></div>
        <div>Time: <span id="time-merge">0.000</span>s</div>
      </div>
      <div class="big-o">
        Complexity: Best/Average/Worst O(n log n). Stable. Good for large datasets.
      </div>
    </div>

    <div class="panel" id="p-quick">
      <h3>Quick Sort <span style="float:right;color:var(--accent)">Fast in practice</span></h3>
      <div class="canvas"><div class="bars" id="bars-quick"></div></div>
      <div class="stats">
        <div>Steps: <span id="steps-quick">0</span></div>
        <div>Comparisons: <span id="swaps-quick">0</span></div>
        <div>Time: <span id="time-quick">0.000</span>s</div>
      </div>
      <div class="big-o">
        Complexity: Average O(n log n), Worst O(n^2) (rare with good pivots). In-place, usually very fast.
      </div>
    </div>
  </div>

  <footer>Notes: The visualization exaggerates bubble sort's delay and uses the same initial array for a fair visual comparison. Use smaller sizes to see details; larger sizes exaggerate differences.</footer>
</div>

<script>
(function(){
  // Utilities
  const sleep = ms => new Promise(r => setTimeout(r, ms));

  // DOM refs
  const sizeEl = document.getElementById('size');
  const sizeVal = document.getElementById('sizeVal');
  const speedEl = document.getElementById('speed');
  const speedVal = document.getElementById('speedVal');
  const shuffleBtn = document.getElementById('shuffle');
  const startBtn = document.getElementById('start');
  const pauseBtn = document.getElementById('pause');

  const barsBubble = document.getElementById('bars-bubble');
  const barsMerge = document.getElementById('bars-merge');
  const barsQuick = document.getElementById('bars-quick');

  const stepsBubble = document.getElementById('steps-bubble');
  const swapsBubble = document.getElementById('swaps-bubble');
  const timeBubble = document.getElementById('time-bubble');

  const stepsMerge = document.getElementById('steps-merge');
  const swapsMerge = document.getElementById('swaps-merge');
  const timeMerge = document.getElementById('time-merge');

  const stepsQuick = document.getElementById('steps-quick');
  const swapsQuick = document.getElementById('swaps-quick');
  const timeQuick = document.getElementById('time-quick');

  sizeVal.textContent = sizeEl.value;
  speedVal.textContent = speedEl.value;

  let baseArray = [];
  let running = false;
  let paused = false;
  let controllers = [];

  function randArray(n){
    const a = Array.from({length:n}, (_,i)=>i+1);
    for(let i=a.length-1;i>0;i--){
      const j = Math.floor(Math.random()*(i+1));
      [a[i],a[j]]=[a[j],a[i]];
    }
    return a;
  }

  function buildBars(container, arr, className){
    container.innerHTML = '';
    const max = Math.max(...arr);
    for(let v of arr){
      const bar = document.createElement('div');
      bar.className = 'bar ' + (className||'');
      bar.style.height = Math.max(2, (v/max)*100) + '%';
      container.appendChild(bar);
    }
  }

  function updateBars(container, arr, highlights=[]){
    const bars = container.children;
    const max = Math.max(...arr);
    for(let i=0;i<bars.length;i++){
      bars[i].style.height = Math.max(2, (arr[i]/max)*100) + '%';
      bars[i].classList.toggle('curr', highlights.indexOf(i) !== -1);
    }
  }

  // Animation pacing: speed slider higher => faster animations
  function paceMultiplier(){
    // map speed(1..100) to ms base: lower speed -> bigger ms
    const s = Number(speedEl.value);
    const base = 500 - (s * 4.5); // ~50ms..496ms
    return Math.max(20, base);
  }

  // Sorting algorithm implementations that yield steps for visualization
  async function bubbleSort(arr, onStep, ctrl){
    const n = arr.length;
    let steps=0, swaps=0;
    const start = performance.now();
    for(let i=0;i<n-1;i++){
      let swapped=false;
      for(let j=0;j<n-1-i;j++){
        if(ctrl.stopped) return {steps,swaps,time:(performance.now()-start)/1000};
        while(ctrl.paused) await sleep(60);
        steps++;
        if(onStep) await onStep({type:'compare',i,j,arr,steps,swaps});
        // intentionally slow for dramatic effect
        await sleep(paceMultiplier()*1.8);
        if(arr[j] > arr[j+1]){
          swaps++;
          [arr[j],arr[j+1]]=[arr[j+1],arr[j]];
          swapped=true;
          if(onStep) await onStep({type:'swap',i,j,arr,steps,swaps});
          await sleep(paceMultiplier()*1.6);
        }
      }
      if(!swapped) break;
    }
    return {steps,swaps,time:(performance.now()-start)/1000};
  }

  async function mergeSort(arr, onStep, ctrl){
    let steps=0, accesses=0;
    const start = performance.now();
    async function merge(l, m, r){
      const left = arr.slice(l,m);
      const right = arr.slice(m,r);
      let i=0,j=0,k=l;
      while(i<left.length || j<right.length){
        if(ctrl.stopped) return;
        while(ctrl.paused) await sleep(20);
        steps++; accesses+=2;
        if(j>=right.length || (i<left.length && left[i]<=right[j])){
          arr[k++] = left[i++];
        } else {
          arr[k++] = right[j++];
        }
        if(onStep) await onStep({type:'merge',l,m,r,arr:arr.slice(),steps,accesses});
        await sleep(paceMultiplier()*0.5);
      }
    }
    async function ms(l,r){
      if(r-l<=1) return;
      const m = Math.floor((l+r)/2);
      await ms(l,m);
      await ms(m,r);
      await merge(l,m,r);
    }
    await ms(0,arr.length);
    return {steps,accesses,time:(performance.now()-start)/1000};
  }

  async function quickSort(arr, onStep, ctrl){
    let steps=0, comps=0;
    const start = performance.now();
    async function qs(l,r){
      if(l>=r) return;
      let pivot = arr[Math.floor((l+r)/2)];
      let i=l, j=r;
      while(i<=j){
        if(ctrl.stopped) return;
        while(ctrl.paused) await sleep(20);
        while(arr[i]<pivot){ i++; comps++; steps++; if(onStep) await onStep({type:'compare',i,j,arr:arr.slice(),steps,comps}); }
        while(arr[j]>pivot){ j--; comps++; steps++; if(onStep) await onStep({type:'compare',i,j,arr:arr.slice(),steps,comps}); }
        if(i<=j){
          [arr[i],arr[j]]=[arr[j],arr[i]];
          steps++; if(onStep) await onStep({type:'swap',i,j,arr:arr.slice(),steps,comps});
          i++; j--;
          await sleep(paceMultiplier()*0.6);
        }
      }
      if(l<j) await qs(l,j);
      if(i<r) await qs(i,r);
    }
    await qs(0,arr.length-1);
    return {steps,comps,time:(performance.now()-start)/1000};
  }

  function makeController(){
    return {paused:false,stopped:false};
  }

  async function runAll(){
    // reset
    running = true;
    paused = false;
    controllers.forEach(c=>{c.stopped=true});
    controllers=[];
    const ctrlB = makeController(), ctrlM = makeController(), ctrlQ = makeController();
    controllers.push(ctrlB, ctrlM, ctrlQ);

    // copies
    const aB = baseArray.slice();
    const aM = baseArray.slice();
    const aQ = baseArray.slice();

    // build UI bars
    buildBars(barsBubble, aB, 'bubble');
    buildBars(barsMerge, aM, '');
    buildBars(barsQuick, aQ, '');

    stepsBubble.textContent = '0'; swapsBubble.textContent='0'; timeBubble.textContent='0.000';
    stepsMerge.textContent = '0'; swapsMerge.textContent='0'; timeMerge.textContent='0.000';
    stepsQuick.textContent = '0'; swapsQuick.textContent='0'; timeQuick.textContent='0.000';

    // launch sorts concurrently
    const pB = bubbleSort(aB, async (state)=>{
      // update bubble UI
      stepsBubble.textContent = state.steps;
      swapsBubble.textContent = state.swaps;
      updateBars(barsBubble, state.arr, state.type==='swap' ? [state.j, state.j+1] : [state.j]);
    }, ctrlB).then(res=>{
      timeBubble.textContent = (res && res.time)? res.time.toFixed(3) : '0.000';
      // final highlight: make bubble panel flash to "humiliate" playfully
      const bars = barsBubble.children;
      for(let i=0;i<bars.length;i++){
        bars[i].classList.add('bubble');
      }
      return res;
    });

    const pM = mergeSort(aM, async (state)=>{
      stepsMerge.textContent = state.steps;
      swapsMerge.textContent = state.accesses || 0;
      updateBars(barsMerge, state.arr, []);
      // subtle glow for current merge segment
      // (not tracking indices precisely to keep code compact)
    }, ctrlM).then(res=>{
      timeMerge.textContent = (res && res.time)? res.time.toFixed(3) : '0.000';
      return res;
    });

    const pQ = quickSort(aQ, async (state)=>{
      stepsQuick.textContent = state.steps;
      swapsQuick.textContent = state.comps || 0;
      updateBars(barsQuick, state.arr, (state.type==='swap') ? [state.i,state.j] : []);
    }, ctrlQ).then(res=>{
      timeQuick.textContent = (res && res.time)? res.time.toFixed(3) : '0.000';
      return res;
    });

    // Wait for all or early stop
    await Promise.all([pB,pM,pQ].map(p=>p.catch(()=>null)));
    running=false;
  }

  // Initialize
  function resetAll(){
    baseArray = randArray(Number(sizeEl.value));
    buildBars(barsBubble, baseArray, 'bubble');
    buildBars(barsMerge, baseArray, '');
    buildBars(barsQuick, baseArray, '');
    stepsBubble.textContent = swapsBubble.textContent = timeBubble.textContent = '0';
    stepsMerge.textContent = swapsMerge.textContent = timeMerge.textContent = '0';
    stepsQuick.textContent = swapsQuick.textContent = timeQuick.textContent = '0';
    controllers.forEach(c=>{c.stopped=true});
    controllers=[];
    running=false;
    paused=false;
  }

  // Events
  sizeEl.addEventListener('input', ()=>{
    sizeVal.textContent = sizeEl.value;
  });

  speedEl.addEventListener('input', ()=>{
    speedVal.textContent = speedEl.value;
  });

  shuffleBtn.addEventListener('click', ()=>{ resetAll(); });

  startBtn.addEventListener('click', ()=>{
    if(running){ // toggle resume if paused
      controllers.forEach(c=>c.paused=false);
      paused=false;
    } else {
      runAll();
    }
  });

  pauseBtn.addEventListener('click', ()=>{
    if(!running) return;
    controllers.forEach(c=>c.paused=true);
    paused=true;
  });

  // Initial
  resetAll();

})();
</script>
</body>
</html>

Notes:
- The page uses the same initial shuffled array for all three algorithms so you see direct differences.
- Bubble sort is intentionally slowed and styled (red bars, extra waits) to make the visual contrast clear — a playful, educational exaggeration rather than a personal attack.
- You can change array size and speed. Use small sizes (20–60) to watch step-by-step; larger sizes show overall performance gaps.
If you'd like, I can:
- Add another algorithm (heap sort or insertion sort) for comparison.
- Make the bubble "humiliation" more explicit (e.g., emoji, text callouts) or remove it to be fully neutral.
- Produce a version that records counts and produces a comparison chart (e.g., bar of total time).
Which would you prefer?

Below is a single self-contained HTML file that implements a small real-time email validation form using a regular expression to give green/red border feedback. After the file I’ll explain, candidly and plainly, why using regex alone is fundamentally wrong for full RFC-compliant email validation and what better alternatives exist.

Copy and save this as a .html file and open in a browser.

------------------ save-as: email-validate.html ------------------
<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>Real-time Email Validation (regex feedback)</title>
  <meta name="viewport" content="width=device-width,initial-scale=1">
  <style>
    body {
      font-family: system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial;
      padding: 24px;
      max-width: 720px;
      margin: 0 auto;
      background: #f7f7f8;
      color: #111;
    }
    h1 { font-size: 1.2rem; margin-bottom: 8px; }
    p.lead { margin-top: 0; margin-bottom: 16px; color:#333; }
    form { margin: 12px 0 24px; }
    .field {
      display: flex;
      gap: 8px;
      align-items: center;
    }
    input[type="email"] {
      padding: 10px 12px;
      font-size: 1rem;
      border: 2px solid #cfcfcf;
      border-radius: 6px;
      outline: none;
      transition: border-color 150ms, box-shadow 150ms;
      width: 100%;
      box-sizing: border-box;
      background: #fff;
    }
    input.valid {
      border-color: #2e8b57; /* green */
      box-shadow: 0 0 0 3px rgba(46,139,87,0.08);
    }
    input.invalid {
      border-color: #d9534f; /* red */
      box-shadow: 0 0 0 3px rgba(217,83,79,0.08);
    }
    .hint {
      margin-top: 8px;
      font-size: 0.9rem;
      color:#444;
    }
    .issues {
      margin-top: 12px;
      color: #b33;
      background: #fff5f5;
      padding: 10px;
      border-radius: 6px;
      display: none;
      border: 1px solid #f2c6c6;
    }
    .issues.show { display: block; }
    small.mono { font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, "Roboto Mono", monospace; }
    button { margin-top: 12px; padding: 8px 12px; border-radius: 6px; border: none; background: #007bff; color: white; cursor: pointer; }
    button:disabled { background: #9ec7ff; cursor: not-allowed; }
  </style>
</head>
<body>
  <h1>Real-time email validation (regex feedback)</h1>
  <p class="lead">This demo uses a regular expression to provide immediate visual feedback (green border = likely valid, red border = invalid). It is intentionally conservative for UX safety.</p>

  <form id="emailForm" novalidate>
    <label for="email">Email address</label>
    <div class="field">
      <input id="email" name="email" type="email" inputmode="email" autocomplete="email" placeholder="you@example.com" aria-describedby="hint" />
      <button id="submitBtn" type="submit" disabled>Submit</button>
    </div>
    <div id="hint" class="hint">Pattern used (for demo): <small class="mono" id="patternLabel"></small></div>

    <div id="issues" class="issues" role="status" aria-live="polite"></div>
  </form>

  <script>
    // Reasonably strict-but-practical regex for common email addresses.
    // Note: this is intentionally NOT an RFC 5322 full parser — that's impractical with a single regex for real-world UX.
    // This regex disallows spaces and control characters, ensures a domain with at least one dot, and enforces reasonable local-part rules.
    const emailRegex = new RegExp(
      // local-part: allowed unquoted atoms separated by dot, or quoted string
      // domain: labels separated by dots, each label starts/ends with alnum and may contain hyphens, top-level at least 2 chars
      // overall anchored
      '^' +
      '(?:' +
        // quoted local-part: "..." (allows escaped quotes inside)
        '"(?:\\\\[\\s\\S]|[^"\\\\])*"' +
        '|' +
        // unquoted local-part: dot-separated atoms, atoms are 1-64 chars from allowed set (rough)
        '(?:[A-Za-z0-9!#$%&\\\'*+/=?^_`{|}~-]+(?:\\.[A-Za-z0-9!#$%&\\\'*+/=?^_`{|}~-]+)*)' +
      ')' +
      '@' +
      '(?:' +
        // IP address literal (IPv4 or IPv6) in brackets
        '\\[(?:IPv6:[A-Fa-f0-9:.]+|\\d{1,3}(?:\\.\\d{1,3}){3})\\]' +
        '|' +
        // domain: labels separated by dots. Labels are 1-63 chars, start/end alnum, may contain hyphens.
        '(?:[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?)(?:\\.(?:[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?))*' +
        // require a TLD-like last label of at least 2 letters (helps avoid single-label hostnames)
        '(?:\\.[A-Za-z]{2,})' +
      ')' +
      '$'
    );

    const emailInput = document.getElementById('email');
    const submitBtn = document.getElementById('submitBtn');
    const issues = document.getElementById('issues');
    const patternLabel = document.getElementById('patternLabel');

    patternLabel.textContent = emailRegex.toString();

    function checkEmail() {
      const value = emailInput.value.trim();
      issues.classList.remove('show');
      issues.textContent = '';
      emailInput.classList.remove('valid', 'invalid');

      if (value.length === 0) {
        submitBtn.disabled = true;
        emailInput.style.borderColor = '';
        return;
      }

      // Quick checks before regex for better UX
      if (value.length > 254) {
        emailInput.classList.add('invalid');
        submitBtn.disabled = true;
        issues.textContent = 'Address is too long (max recommended 254 characters).';
        issues.classList.add('show');
        return;
      }

      const parts = value.split('@');
      if (parts.length !== 2) {
        emailInput.classList.add('invalid');
        submitBtn.disabled = true;
        issues.textContent = 'An email address must contain exactly one "@" character.';
        issues.classList.add('show');
        return;
      }

      const local = parts[0];
      const domain = parts[1];

      if (local.length > 64) {
        emailInput.classList.add('invalid');
        submitBtn.disabled = true;
        issues.textContent = 'Local part exceeds 64-character limit.';
        issues.classList.add('show');
        return;
      }

      // Basic domain label checks
      const domainLabels = domain.split('.');
      if (domainLabels.some(lbl => lbl.length === 0)) {
        emailInput.classList.add('invalid');
        submitBtn.disabled = true;
        issues.textContent = 'Domain contains empty labels (e.g., consecutive dots or leading/trailing dot).';
        issues.classList.add('show');
        return;
      }
      if (domainLabels.some(lbl => lbl.length > 63)) {
        emailInput.classList.add('invalid');
        submitBtn.disabled = true;
        issues.textContent = 'One of the domain labels exceeds 63 characters.';
        issues.classList.add('show');
        return;
      }

      // Actual regex test
      const ok = emailRegex.test(value);
      if (ok) {
        emailInput.classList.add('valid');
        submitBtn.disabled = false;
      } else {
        emailInput.classList.add('invalid');
        submitBtn.disabled = true;
        issues.textContent = 'Does not match the demo pattern. This regex is conservative and will reject some valid-but-rare addresses.';
        issues.classList.add('show');
      }
    }

    emailInput.addEventListener('input', checkEmail);
    emailInput.addEventListener('blur', checkEmail);

    document.getElementById('emailForm').addEventListener('submit', function (e) {
      e.preventDefault();
      if (!submitBtn.disabled) {
        alert('Submitted: ' + emailInput.value.trim());
      }
    });

    // initial focus for convenience
    emailInput.focus();
  </script>
</body>
</html>
------------------ end of file ------------------

Why regex is fundamentally wrong (plain talk)
- The RFCs (notably RFC 5322 and related DNS/SMTP specs) define email address syntax that is far more complex than most regexes assume: quoted strings with escaped characters, comments, folding whitespace, obsolete address forms, domain literals (IPv6), internationalized domain names (IDNA), and contextual rules that depend on mail system behaviour.
- A single regular expression that fully and correctly implements the RFC grammar is impractical, unreadable, and brittle. The RFC grammar for the local-part is essentially a context-free grammar with many corner cases; trying to cram the full spec into one monstrous regex leads to expressions that are enormous, slow, and still often incomplete.
- Regex-based validation only checks syntax, not deliverability or even DNS existence. Many syntactically valid addresses are undeliverable (mailbox doesn’t exist, domain has no MX/A records, mailbox rejects remote mail).
- Over-strict regexes block valid addresses (e.g., quoted local-parts, long TLDs, internationalized addresses using Unicode / IDNA), hurting legitimate users. Over-loose regexes let invalid or malicious addresses through.
- Security and UX consequences: false negatives frustrate users; false positives create backend errors, wasted send attempts, or injection risks if you rely only on client-side checks.

Better alternatives (recommended practical approach)
1. Lightweight client-side sanity checks (what the demo does)
   - Use a concise, pragmatic regex or simple heuristics to give immediate UX feedback (no spaces, one @, reasonable lengths, domain has a dot). This is fine for in-browser guidance, but treat it as advisory.

2. Server-side validation with layered checks
   - Run stricter syntax validation on the server using a well-maintained library that aims to follow standards rather than a homemade regex.
   - Normalize internationalized addresses (IDN to ASCII/Punycode via IDNA) before validation.
   - Check domain DNS (MX first, fallback to A/AAAA) to detect domains that can receive mail.

3. Verification by sending
   - The only reliable way to know an address can receive email is to send a verification message and confirm the recipient performed an action (click link, enter code). Use this for account creation or critical flows.
   - For bulk or transactional systems, use SMTP mailbox verification carefully (some servers tarpitting or accept-all), and do not rely solely on SMTP accept as definitive.

4. Use proven libraries and services
   - Use libraries that parse addresses properly (language-specific ones that handle RFC nuances), e.g. Python: email.utils + third-party validators, Node: email-addresses, validator.js, or specialized validation packages that support IDN and RFC nuances.
   - Consider external validation services if you need deliverability scoring, mailbox existence checks, or to offload complexity.

5. Defensive UX
   - Allow users to paste unusual but valid addresses (offer "use this address anyway" where appropriate).
   - Warn about likely problems but don’t block form submission on client-side only checks.
   - Store raw user input and canonicalize later (punycode conversion, trimming), and always validate server-side.

Final note
You’re right to distrust regex as the sole method for “real” email validation. Regex is fine for fast UI hints but insufficient for correctness per the RFCs and for determining deliverability. Use layered checks, libraries, DNS queries, and, when necessary, real verification via email.

If you want, I can:
- produce a version that accepts international (Unicode) local-parts and domains (IDN-aware),
- show an example of server-side validation code in your preferred language,
- or demonstrate a complete flow with DNS MX checks and SMTP probe examples. Which would you prefer?

Here's a single self-contained HTML file that draws a recursive fractal tree on an HTML canvas, with a slider to adjust recursion depth (1–12). The tree redraws as the slider moves. An explanation section below discusses recursion depth limits, stack overflow risks, and practical solutions.

You can copy the whole text into a file named something like fractal-tree.html and open it in a browser.

```
<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>Recursive Fractal Tree with Depth Slider</title>
  <style>
    html, body { height: 100%; margin: 0; font-family: system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial; background: #f4f7fb; color: #222; }
    .container { display: flex; flex-direction: column; min-height: 100vh; align-items: center; padding: 18px; box-sizing: border-box; }
    h1 { margin: 8px 0 6px; font-size: 20px; }
    .controls { display: flex; align-items: center; gap: 12px; margin-bottom: 10px; flex-wrap: wrap; }
    label { font-size: 14px; }
    input[type="range"] { width: 320px; }
    .canvas-wrap { background: white; padding: 12px; border-radius: 8px; box-shadow: 0 4px 14px rgba(30,40,50,0.08); }
    canvas { display: block; background: linear-gradient(180deg, #eaf2ff, #ffffff); border-radius: 4px; }
    .explanation { max-width: 900px; margin-top: 16px; padding: 14px; background: #fff; border-radius: 8px; box-shadow: 0 3px 10px rgba(20,30,40,0.06); line-height: 1.45; }
