  <script>
    /*
      ThemeManager singleton
      - Controls theme state ('light' | 'dark')
      - Persists selection to localStorage
      - Exposes subscribe() for components to react to changes
      - Applies theme by setting document.documentElement.dataset.theme
      - Optionally follows system preference
    */
    const ThemeManager = (function () {
      // Private variables (enclosed)
      let instance = null;

      // Create the manager (factory)
      function createInstance() {
        const KEY = 'theme.preference.v1';
        const subscribers = new Set();
        let theme = 'light';
        let followSystem = false;

        // Detect system preference
        const mql = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)');
        function getSystem() {
          return (mql && mql.matches) ? 'dark' : 'light';
        }

        // Load from storage + system fallback
        function load() {
          try {
            const stored = localStorage.getItem(KEY);
            if (stored === 'light' || stored === 'dark') {
              theme = stored;
            } else {
              theme = getSystem();
            }
          } catch (e) {
            theme = getSystem();
          }
        }

        // Apply to document
        function applyTheme() {
          // set a data attribute on <html>
          document.documentElement.dataset.theme = theme;
          // notify subscribers
          subscribers.forEach(fn => {
            try { fn(theme); } catch (err) { console.error('subscriber error', err); }
          });
        }

        function setTheme(t, { persist = true } = {}) {
          if (t !== 'dark' && t !== 'light') return;
          theme = t;
          if (persist) {
            try { localStorage.setItem(KEY, theme); } catch (e) { /* ignore */ }
          }
          applyTheme();
        }

        function toggle() {
          setTheme(theme === 'dark' ? 'light' : 'dark');
        }

        function getTheme() {
          return theme;
        }

        // system follow toggle: if enabled, listen to mql changes
        function setFollowSystem(v) {
          followSystem = !!v;
          if (followSystem) {
            // adopt system immediately
            setTheme(getSystem(), { persist: false });
            if (mql && mql.addEventListener) {
              mql.addEventListener('change', onSystemChange);
            } else if (mql && mql.addListener) {
              mql.addListener(onSystemChange);
            }
          } else {
            if (mql && mql.removeEventListener) {
              mql.removeEventListener('change', onSystemChange);
            } else if (mql && mql.removeListener) {
              mql.removeListener(onSystemChange);
            }
          }
        }

        function onSystemChange(e) {
          if (followSystem) {
            setTheme(e.matches ? 'dark' : 'light', { persist: false });
          }
        }

        // subscribe / unsubscribe
        function subscribe(fn) {
          if (typeof fn !== 'function') return () => {};
          subscribers.add(fn);
          // call immediately with current value
          try { fn(theme); } catch (e) { /* ignore */ }
          return () => subscribers.delete(fn);
        }

        // initialize
        load();
        applyTheme();

        return {
          setTheme,
          toggle,
          getTheme,
          subscribe,
          setFollowSystem,
          isFollowingSystem: () => !!followSystem,
        };
      }

      return {
        getInstance: function () {
          if (!instance) instance = createInstance();
          return instance;
        }
      };
    })();

    // ------- Example wiring: connect UI to ThemeManager -------
    (function () {
      const mgr = ThemeManager.getInstance();

      // Elements
      const toggle = document.getElementById('themeToggle');
      const toggleDot = toggle.querySelector('.dot');
      const currentThemeEl = document.getElementById('currentTheme');
      const prefersSystem = document.getElementById('prefersSystem');
      const setLight = document.getElementById('setLight');
      const setDark = document.getElementById('setDark');

      // subscribe to theme changes to update UI
      mgr.subscribe((theme) => {
        const on = theme === 'dark';
        toggle.dataset.on = on ? 'true' : 'false';
        toggle.setAttribute('aria-pressed', on ? 'true' : 'false');
        // change dot color subtly when dark
        toggleDot.style.boxShadow = on ? '0 2px 6px rgba(255,255,255,0.06) inset' : '0 2px 6px rgba(0,0,0,0.12) inset';
        currentThemeEl.textContent = theme;
      });

      // wire click
      toggle.addEventListener('click', () => {
        mgr.toggle();
      });

      // buttons
      setLight.addEventListener('click', () => mgr.setTheme('light'));
      setDark.addEventListener('click', () => mgr.setTheme('dark'));

      // prefers system
      prefersSystem.addEventListener('change', (e) => {
        mgr.setFollowSystem(e.target.checked);
      });

      // initialize checkbox from manager state (if it were persisted)
      prefersSystem.checked = mgr.isFollowingSystem();
    })();
  </script>
</body>
</html>

Discussion — Singleton for Theme State

What the demo does
- ThemeManager is a classic singleton: ThemeManager.getInstance() always returns the same manager object. It holds theme state, applies the theme to document.documentElement, persists to localStorage, and exposes subscribe(fn) for components to react to changes.
- UI controls (toggle, buttons, checkboxes) use the singleton so they do not need to pass theme values around; any part of the page can call ThemeManager.getInstance() to read or update the theme.
- The manager also optionally follows system color-scheme preference and updates when it changes.

Pros of this singleton approach
- Centralized state: The theme is maintained in one place. Components don't need to coordinate or duplicate logic.
- Easy access: Any module or UI element can get the instance and query or set the theme without prop-drilling or importing many modules.
- Simple subscription model: subscribe(fn) makes it easy for components to react to state changes.
- Lightweight: For a small app or simple cross-cutting concerns (theme, authentication token, feature flags), singletons are straightforward and low-overhead.
- Persistence encapsulation: The singleton handles saving/loading from localStorage so individual components don't repeat that logic.

Cons and pitfalls
- Global mutable state: Singletons are effectively global variables. This can make reasoning about state changes harder in large apps because any code can mutate the singleton at any time.
- Tight coupling: Components that call ThemeManager.getInstance() are tightly coupled to that concrete implementation. This makes testing harder (you need to mock or reset the singleton) and reduces reusability.
- Hidden dependencies: When a component uses a singleton directly, the dependency is implicit rather than explicit; it's not visible from the component's API/props.
- Lifecycle & initialization complexity: Ensuring singletons initialize correctly (and reset in tests) can be trickier than controlled injection.
- Scaling: As your application grows, the singleton can accumulate many responsibilities and become an anti-pattern (God object).

When to prefer alternatives like Dependency Injection (DI)
- Testability: DI lets you pass a mock or fake theme manager into components in tests; singletons require manipulating global state (or replacing the singleton instance) to test behavior.
- Explicit dependencies: With DI, a component declares what it needs (e.g., via constructor, props, or context). This improves clarity and makes refactoring safer.
- Multiple instances: If you need multiple independent theme managers (for example, isolated iframes or embeddable widgets that should maintain their own themes), DI supports creating separate instances easily; singletons do not.
- Larger architectures / apps: In medium-to-large apps, application state is usually handled through scoped stores or DI-enabled services (or state management libraries like Redux, MobX, or Context in React). These provide clearer data flow, time-travel debugging, middleware, and better test support.
- Pluginability and swaps: When you want to swap implementations at runtime (e.g., a different storage backend, or server-driven theming), DI makes this easier without changing dependent code.

A middle ground
- Use a single, well-encapsulated service for cross-cutting state but expose it via a controlled API and/or a provider/context pattern. For example, in React you'd often use a Context Provider that internally uses a single manager but still allows tests to supply a different provider. This gives the convenience of a singleton with better explicitness and testability.
- Make the singleton minimal (one responsibility) and small. Avoid turning it into a catch-all object.

Testing and cleanup tips when using singletons
- Provide a way to reset or reinitialize state (not shown in the demo for brevity) — useful in unit tests.
- Keep mutation surface small: don't expose direct internal mutation; use dedicated methods (setTheme, toggle).
- Mock localStorage or wrap persistence behind another testable abstraction.

When a singleton is appropriate for theming
- Small sites or widgets where simplicity matters.
- When global shared state is truly global (there's only one theme for the entire document).
- Prototypes or demos where quick central control is beneficial.

When to avoid singletons
- Large applications that demand test isolation, modularity, and clear dependencies.
- When multiple independent instances of the service are needed.
- When you need to swap or mock the service frequently across many tests.

If you want, I can:
- Provide a variant that uses a dependency-injection approach (for plain JS modules) or a React/Angular/Vue example that uses provider/context patterns.
- Add test hooks (reset) to the singleton for easier testing.
- Add event-based architecture (CustomEvent) instead of subscribe/unsubscribe.

