  <script>
    /*
      ThemeSingleton
      - Use an IIFE to create a single instance
      - Exposes: getTheme(), setTheme('light'|'dark'), toggle(), subscribe(fn), unsubscribe(fn)
      - Persists to localStorage key 'theme'
    */
    const ThemeSingleton = (function () {
      const STORAGE_KEY = 'theme';
      let instance = null;

      function createInstance() {
        // Allowed values
        const THEMES = { LIGHT: 'light', DARK: 'dark' };

        // initial theme: try localStorage, otherwise prefer system dark media query
        const saved = (function () {
          try { return localStorage.getItem(STORAGE_KEY); } catch (e) { return null; }
        })();

        let theme = saved === THEMES.LIGHT || saved === THEMES.DARK
          ? saved
          : (window.matchMedia && window.matchMedia('(prefers-color-scheme: light)').matches ? THEMES.LIGHT : THEMES.DARK);

        const subscribers = new Set();

        function persist() {
          try { localStorage.setItem(STORAGE_KEY, theme); } catch (e) { /* ignore */ }
        }

        function notify() {
          subscribers.forEach(fn => {
            try { fn(theme); } catch (e) { console.error('Theme subscriber error', e); }
          });
        }

        // apply to document root
        function applyDocument() {
          const root = document.documentElement;
          if (theme === THEMES.LIGHT) {
            root.classList.add('theme-light');
          } else {
            root.classList.remove('theme-light');
          }
        }

        function getTheme() { return theme; }
        function setTheme(t) {
          if (t !== THEMES.LIGHT && t !== THEMES.DARK) return;
          if (theme === t) return;
          theme = t;
          persist();
          applyDocument();
          notify();
        }
        function toggle() {
          setTheme(theme === THEMES.LIGHT ? THEMES.DARK : THEMES.LIGHT);
        }
        function subscribe(fn) {
          subscribers.add(fn);
          // call immediately to initialize subscriber with current theme
          try { fn(theme); } catch (e) { console.error('Subscriber init error', e); }
        }
        function unsubscribe(fn) { subscribers.delete(fn); }

        // initialize
        applyDocument();

        return {
          THEMES,
          getTheme,
          setTheme,
          toggle,
          subscribe,
          unsubscribe
        };
      }

      return {
        getInstance: function () {
          if (!instance) instance = createInstance();
          return instance;
        }
      };
    })();

    // Usage: multiple UI parts subscribe to the singleton and get updates
    (function () {
      const themeManager = ThemeSingleton.getInstance();

      // header toggle UI
      const themeToggle = document.getElementById('themeToggle');
      const toggleIcon = document.getElementById('toggleIcon');
      const toggleLabel = document.getElementById('toggleLabel');

      themeToggle.addEventListener('click', () => themeManager.toggle());

      // display current theme in aside
      const currentThemeEl = document.getElementById('currentTheme');

      // change text/icon of toggle and currentTheme
      function updateToggleUI(theme) {
        if (theme === themeManager.THEMES.LIGHT) {
          toggleIcon.textContent = '☀️';
          toggleLabel.textContent = 'Light';
        } else {
          toggleIcon.textContent = '🌙';
          toggleLabel.textContent = 'Dark';
        }
      }

      themeManager.subscribe(theme => {
        // update some UI elements that depend on the theme
        updateToggleUI(theme);
        currentThemeEl.textContent = theme.toUpperCase();
      });

      // some other components also subscribe:
      // code block theme-ish text (just to demonstrate observer usage)
      const codeBlock = document.getElementById('codeBlock');
      themeManager.subscribe(theme => {
        if (theme === themeManager.THEMES.LIGHT) {
          codeBlock.textContent = "// ThemeSingleton (light mode)\n// Current theme: " + theme;
        } else {
          codeBlock.textContent = "// ThemeSingleton (dark mode)\n// Current theme: " + theme;
        }
      });

      // Buttons change style slightly to show dynamic reaction
      const btnAccent = document.getElementById('btnAccent');
      const btnGhost = document.getElementById('btnGhost');
      themeManager.subscribe(theme => {
        if (theme === themeManager.THEMES.LIGHT) {
          btnGhost.style.borderStyle = 'dashed';
          btnGhost.style.background = 'transparent';
        } else {
          btnGhost.style.borderStyle = 'dashed';
          btnGhost.style.background = 'transparent';
        }
      });

      // two explicit set buttons
      document.getElementById('setLight').addEventListener('click', () => themeManager.setTheme(themeManager.THEMES.LIGHT));
      document.getElementById('setDark').addEventListener('click', () => themeManager.setTheme(themeManager.THEMES.DARK));

      // demonstrate that multiple independent subscribers can be added and removed:
      const dynamicSubscriber = (theme) => {
        console.log('dynamic subscriber got theme:', theme);
      };
      themeManager.subscribe(dynamicSubscriber);
      // remove after 10s just as a demo (won't affect other subscribers)
      setTimeout(() => themeManager.unsubscribe(dynamicSubscriber), 10000);

      // Expose for debugging on window (not necessary, but helpful during dev)
      window.__themeManager = themeManager;
    })();
  </script>
</body>
</html>

Notes (short discussion included on the page):
- Pros of Singleton: simple to access, single source of truth, good for small to medium apps when you want centralized state without wiring DI.
- Cons of Singleton: implicit coupling, harder to unit-test, global lifecycle, can hide dependencies.
- When to use Dependency Injection: if you need to swap implementations (e.g., different theme providers), want easier testing/mocking, different lifecycles per scope (e.g., per user or per module), or to avoid globals in large applications.

