        <button id="fixedBtn" class="primary">+1 (fixed)</button>
        <button id="fixedReset" class="warn">Reset</button>
      </div>
      <div class="explain">
        Fix used: serialize updates so each async operation runs after the previous completes.
        This demo implements a simple promise chain (operation queue / mutex). Each click appends a task to the chain.
      </div>
      <div class="note">
        Because updates are serialized, rapid clicks are all applied in order — no stale overwrites.
      </div>
      <div style="margin-top:12px;">
        <div style="font-weight:700; margin-bottom:4px;">Fixed internal log (latest events):</div>
        <div id="fixedLog" class="log"></div>
      </div>
    </div>
  </div>

  <script>
    // Utility: append log line and keep last lines visible
    function appendLog(el, text) {
      const now = new Date().toLocaleTimeString();
      el.textContent = now + '  ' + text + '\\n' + el.textContent;
      // trim to reasonable length
      const lines = el.textContent.split('\\n').slice(0, 200).join('\\n');
      el.textContent = lines;
    }

    // Simulated async increment that takes a small random delay to exaggerate races
    function simulatedAsyncDelay(fn, label) {
      const delay = 30 + Math.floor(Math.random() * 120); // 30..150ms
      return new Promise(resolve => {
        setTimeout(() => {
          try { fn(); } catch (e) { console.error(e); }
          resolve();
        }, delay);
      });
    }

    // -----------------------
    // Buggy counter implementation
    // -----------------------
    (function() {
      const shared = { count: 0 }; // shared variable
      const sharedEl = document.getElementById('buggyShared');
      const display = document.getElementById('buggyDisplay');
      const btn = document.getElementById('buggyBtn');
      const reset = document.getElementById('buggyReset');
      const logEl = document.getElementById('buggyLog');

      function render() {
        sharedEl.textContent = String(shared.count);
        display.textContent = String(shared.count);
      }

      // The buggy update:
      // 1) read shared.count into local "readValue"
      // 2) start async work (setTimeout)
      // 3) when async completes, compute newValue = readValue + 1 and write shared.count = newValue
      // Because multiple clicks do this in parallel, they can read stale values and later overwrite newer ones.
      btn.addEventListener('click', () => {
        const readValue = shared.count;
        appendLog(logEl, 'CLICK -> read=' + readValue + ' (scheduling async increment)');
        // start async update that uses the stale readValue
        simulatedAsyncDelay(() => {
          const newValue = readValue + 1;
          shared.count = newValue;               // overwrite shared with value based on stale read
          appendLog(logEl, 'ASYNC DONE -> wrote=' + newValue + ' (based on read=' + readValue + ')');
          render();
        }, 'buggy');
      });

      reset.addEventListener('click', () => {
        shared.count = 0;
        render();
        logEl.textContent = '';
      });

      render();
    })();

    // -----------------------
    // Fixed counter implementation (operation queue / serialized updates)
    // -----------------------
    (function() {
      const shared = { count: 0 };
      const sharedEl = document.getElementById('fixedShared');
      const display = document.getElementById('fixedDisplay');
      const btn = document.getElementById('fixedBtn');
      const reset = document.getElementById('fixedReset');
      const logEl = document.getElementById('fixedLog');

      function render() {
        sharedEl.textContent = String(shared.count);
        display.textContent = String(shared.count);
      }

      // Simple "queue" / promise chain that ensures updates run in sequence.
      // start with a resolved promise
      let chain = Promise.resolve();

      function enqueueUpdate(fn) {
        // Append to the chain. Each fn should return a promise (the async work).
        chain = chain.then(() => fn()).catch(err => {
          console.error('Chain error', err);
          // continue the chain even if error occurs
        });
      }

      btn.addEventListener('click', () => {
        appendLog(logEl, 'CLICK -> enqueue increment task');
        enqueueUpdate(() => {
          // Read-modify-write happens inside the serialized task, so no concurrent reads.
          const readValue = shared.count;
          appendLog(logEl, 'TASK START -> read=' + readValue);
          // simulated async work (delay) but it's serialized: next task won't start until this completes
          return simulatedAsyncDelay(() => {
            const newValue = readValue + 1;
            shared.count = newValue;
            appendLog(logEl, 'TASK DONE -> wrote=' + newValue + ' (based on read=' + readValue + ')');
            render();
          }, 'fixed');
        });
      });

      reset.addEventListener('click', () => {
        // resetting should also wait for/push to the chain to avoid races with in-flight tasks.
        // For demo simplicity we'll clear the chain and reset immediately.
        chain = Promise.resolve();
        shared.count = 0;
        render();
        logEl.textContent = '';
      });

      render();
    })();

    // Initial user guidance: focus on spam clicking
    document.addEventListener('DOMContentLoaded', () => {
      // nothing
    });
  </script>
</body>
</html>
```

Explanation summary (visible on the page):
- The bug occurs because each click reads the shared count synchronously, then performs an asynchronous delay and later writes count = read + 1. If two clicks read the same count before either finishes, both will write the same next value, losing one increment (or overwriting a newer value).
- The fix shown serializes updates (a simple promise queue). Each increment runs only after the previous finishes, so every click's read-modify-write sees the latest value and no stale overwrites occur.

If you prefer a different fix (for example, atomic compare-and-swap style, using an increment function that applies relative deltas rather than reads, or using AbortController to cancel previous updates), tell me which approach and I can modify the example.

I built a single self-contained HTML file that renders a clean, zoomable, interactive singly linked list visualization with properly drawn arrows, nicely spaced node boxes, and the four operations you requested: insert at head, insert at tail, delete by value, and search with visual highlighting. It also handles the empty-list state and animates pointer movement so the arrows remain correct.

