<script>
(function(){
  // Model for singly linked list
  class Node {
    constructor(val){
      this.val = val;
      this.next = null;
      this.id = Node._nextId++;
    }
  }
  Node._nextId = 1;

  class LinkedList {
    constructor(){
      this.head = null;
      this.size = 0;
    }
    insertHead(val){
      const n = new Node(val);
      n.next = this.head;
      this.head = n;
      this.size++;
      return n;
    }
    insertTail(val){
      const n = new Node(val);
      if(!this.head){
        this.head = n;
      } else {
        let cur = this.head;
        while(cur.next) cur = cur.next;
        cur.next = n;
      }
      this.size++;
      return n;
    }
    deleteByValue(val){
      if(!this.head) return null;
      if(this.head.val === val){
        const rem = this.head;
        this.head = this.head.next;
        rem.next = null;
        this.size--;
        return rem;
      }
      let prev = this.head;
      let cur = this.head.next;
      while(cur){
        if(cur.val === val){
          prev.next = cur.next;
          cur.next = null;
          this.size--;
          return cur;
        }
        prev = cur;
        cur = cur.next;
      }
      return null;
    }
    find(val){
      let idx = 0;
      let cur = this.head;
      while(cur){
        if(cur.val === val) return {node:cur, index:idx};
        cur = cur.next; idx++;
      }
      return null;
    }
    toArray(){
      const arr = [];
      let cur = this.head;
      while(cur){ arr.push(cur); cur = cur.next; }
      return arr;
    }
    clear(){ this.head = null; this.size = 0; }
  }

  // Renderer constants
  const NODE_WIDTH = 110;
  const NODE_GAP = 28;
  const NODE_HEIGHT = 44;
  const BOX_PAD_X = 8;

  // DOM
  const svg = document.getElementById('svg');
  const nodesGroup = document.getElementById('nodes');
  const emptyIndicator = document.getElementById('empty-indicator');
  const headPointer = document.getElementById('head-pointer');
  const statusBox = document.getElementById('status');
  const input = document.getElementById('input-value');
  const btnInsertHead = document.getElementById('btn-insert-head');
  const btnInsertTail = document.getElementById('btn-insert-tail');
  const btnDelete = document.getElementById('btn-delete');
  const btnSearch = document.getElementById('btn-search');
  const btnReset = document.getElementById('btn-reset');
  const btnRandom = document.getElementById('btn-random');
  const viz = document.getElementById('viz');

  const list = new LinkedList();

  // Utility: create SVG element
  function make(tag, attrs = {}) {
    const el = document.createElementNS('http://www.w3.org/2000/svg', tag);
    for(const k in attrs) el.setAttribute(k, attrs[k]);
    return el;
  }

  // Render list
  function render(){
    // clear
    while(nodesGroup.firstChild) nodesGroup.removeChild(nodesGroup.firstChild);

    const arr = list.toArray();
    if(arr.length === 0){
      emptyIndicator.style.display = 'block';
      headPointer.style.display = 'none';
      statusBox.textContent = 'List is empty';
      statusBox.className = 'status card';
      // center empty indicator
      return;
    } else {
      emptyIndicator.style.display = 'none';
      headPointer.style.display = 'block';
      statusBox.textContent = 'Size: ' + list.size;
      statusBox.className = 'status card ok';
    }

    // compute total width and update svg viewBox width dynamically
    const totalWidth = arr.length * (NODE_WIDTH + NODE_GAP) + 200;
    svg.setAttribute('viewBox', `0 0 ${Math.max(1200,totalWidth)} 300`);

    // Draw nodes
    arr.forEach((node, i) => {
      const x = i * (NODE_WIDTH + NODE_GAP);
      const y = 0;

      // group per node
      const g = make('g', { transform: `translate(${x},${y})`, 'data-id': node.id });
      // box background
      const rect = make('rect', { x:0, y:0, rx:8, ry:8, width: NODE_WIDTH, height: NODE_HEIGHT, fill:'#ffffff', stroke:'#e6eef8', 'stroke-width':2 });
      g.appendChild(rect);

      // Value box (left portion)
      const valW = NODE_WIDTH - 36;
      const valRect = make('rect', { x:8, y:6, rx:6, ry:6, width: valW, height: NODE_HEIGHT - 12, fill: '#e9f2ff', stroke:'#2b6cb0', 'stroke-width':2 });
      g.appendChild(valRect);
      const valText = make('text', { x:8 + valW/2, y: NODE_HEIGHT/2 + 4, 'text-anchor':'middle', 'font-size':14, fill:'#0f1724', 'font-weight':600 });
      valText.textContent = String(node.val);
      g.appendChild(valText);

      // next small box
      const nxX = 8 + valW + 8;
      const nxRect = make('rect', { x:nxX, y:8, rx:6, ry:6, width:28, height:28, fill:'#ffffff', stroke:'#cbd5e1' });
      g.appendChild(nxRect);
      const nxText = make('text', { x:nxX + 14, y: NODE_HEIGHT/2 + 4, 'text-anchor':'middle', 'font-size':12, fill:'#6b7280' });
      nxText.textContent = '→';
      g.appendChild(nxText);

      // label (index)
      const idxText = make('text', { x:NODE_WIDTH/2, y: NODE_HEIGHT + 16, 'text-anchor':'middle', 'font-size':11, fill:'#6b7280' });
      idxText.textContent = i;
      g.appendChild(idxText);

      nodesGroup.appendChild(g);

      // Draw arrow to next if exists
      if(node.next){
        const fromX = x + nxX + 28; // right edge of next small box
        const fromY = y + NODE_HEIGHT/2;
        const nextIndex = i + 1;
        const toX = nextIndex * (NODE_WIDTH + NODE_GAP) + 8; // left inner edge of value box of next node
        const toY = y + NODE_HEIGHT/2;

        // straight horizontal path with small curve
        const path = make('path', {
          d: `M ${fromX} ${fromY} C ${fromX+16} ${fromY} ${toX-16} ${toY} ${toX} ${toY}`,
          stroke:'#1f2937', 'stroke-width':2, fill:'none', 'marker-end':'url(#arrow)'
        });
        nodesGroup.appendChild(path);
      } else {
        // last node: optional tail arrow to null (draw small cross)
        const fromX = x + nxX + 28;
        const fromY = y + NODE_HEIGHT/2;
        const cross = make('g', { transform: `translate(${fromX+18},${fromY})`});
        const l1 = make('line', { x1:-6, y1:-6, x2:6, y2:6, stroke:'#cbd5e1', 'stroke-width':2 });
        const l2 = make('line', { x1:-6, y1:6, x2:6, y2:-6, stroke:'#cbd5e1', 'stroke-width':2 });
        cross.appendChild(l1); cross.appendChild(l2);
        nodesGroup.appendChild(cross);
      }
    });

    // Position head pointer: point to first node's value box center
    const firstX = 0;
    const headLine = document.getElementById('head-line');
    const hx1 = 20;
    const hx2 = 20; // arrow marker draws into the nodes area; we'll compute final y
    // compute target coordinates in SVG space
    const targetX = 40 + firstX + 8 + (NODE_WIDTH - 36)/2; // based on group translate + inner offset
    const targetY = 70 + NODE_HEIGHT/2; // group translate y + center
    // update head pointer line to point visually toward first node
    // place head-pointer group near the top-left; draw a line to point at node
    headPointer.setAttribute('transform', `translate(${Math.min(targetX-60, targetX-120)},30)`);
    // move head-line to point roughly toward node (we'll set marker-end)
    headLine.setAttribute('x1', 40);
    headLine.setAttribute('y1', 6);
    headLine.setAttribute('x2', targetX - 40 + 20);
    headLine.setAttribute('y2', targetY - 30);

    // attach data-id to head for easier highlighting
    headPointer.setAttribute('data-target-id', arr[0].id);
  }

  // Helpers to highlight nodes during operations
  function highlightNodeById(id, cls='highlight'){
    // find group with data-id
    const g = nodesGroup.querySelector(`g[data-id='${id}']`);
    if(!g) return;
    // create an overlay rect
    const bb = g.getBBox();
    const overlay = make('rect', { x:bb.x-6, y:bb.y-6, width:bb.width+12, height:bb.height+20, rx:10, fill:'#fff', opacity:0 });
    overlay.classList.add('hl-rect');
    nodesGroup.appendChild(overlay);
    // animate via CSS by applying stroke and shadow (we modify attributes directly)
    overlay.setAttribute('stroke', '#3b82f6');
    overlay.setAttribute('stroke-width', '3');
    overlay.setAttribute('fill', 'rgba(59,130,246,0.06)');
    setTimeout(()=>{ if(overlay && overlay.parentNode) overlay.parentNode.removeChild(overlay); }, 1200);
  }

  // Perform operations with small visual step-throughs
  async function visualInsertHead(val){
    disableControls(true);
    const n = list.insertHead(val);
    render();
    // animate flash of new head node
    highlightNodeById(n.id);
    await sleep(500);
    disableControls(false);
  }

  async function visualInsertTail(val){
    disableControls(true);
    const n = list.insertTail(val);
    render();
    highlightNodeById(n.id);
    await sleep(500);
    disableControls(false);
  }

  async function visualDelete(val){
    disableControls(true);
    if(!list.head){
      flashStatus('List is empty', true);
      disableControls(false);
      return;
    }
    // step through nodes, highlighting probe
    let cur = list.head;
    while(cur){
      render(); // ensure layout exists
      highlightNodeById(cur.id);
      await sleep(450);
      if(cur.val === val){
        // delete and re-render
        list.deleteByValue(val);
        render();
        flashStatus('Deleted: ' + val, false);
        await sleep(450);
        disableControls(false);
        return;
      }
      cur = cur.next;
    }
    flashStatus('Value not found: ' + val, true);
    disableControls(false);
  }

  async function visualSearch(val){
    disableControls(true);
    if(!list.head){
      flashStatus('List is empty', true);
      disableControls(false);
      return;
    }
    let cur = list.head;
    while(cur){
      render();
      highlightNodeById(cur.id);
      await sleep(450);
      if(cur.val === val){
        // persistent highlight
        persistentlyMarkNode(cur.id);
        flashStatus('Found: ' + val, false);
        disableControls(false);
        return;
      }
      cur = cur.next;
    }
    flashStatus('Not found: ' + val, true);
    disableControls(false);
  }

  // small helper to add a persistent mark (green) around a found node
  function persistentlyMarkNode(id){
    const g = nodesGroup.querySelector(`g[data-id='${id}']`);
    if(!g) return;
    const bb = g.getBBox();
    const overlay = make('rect', { x:bb.x-6, y:bb.y-6, width:bb.width+12, height:bb.height+20, rx:10, fill:'rgba(16,185,129,0.06)', stroke:'#10b981', 'stroke-width':3 });
    overlay.setAttribute('data-found','1');
    nodesGroup.appendChild(overlay);
    setTimeout(()=>{ if(overlay && overlay.parentNode) overlay.parentNode.removeChild(overlay); }, 2500);
  }

  // UI helpers
  function flashStatus(msg, isErr){
    statusBox.textContent = msg;
    statusBox.className = 'status card ' + (isErr ? 'err' : 'ok');
    setTimeout(()=>{ statusBox.textContent = list.size ? ('Size: ' + list.size) : 'List is empty'; statusBox.className='status card'; }, 1600);
  }
  function disableControls(dis){
    [btnInsertHead, btnInsertTail, btnDelete, btnSearch, btnReset, btnRandom].forEach(b=>b.disabled = dis);
    if(dis) { [btnInsertHead, btnInsertTail, btnDelete, btnSearch, btnReset, btnRandom].forEach(b=>b.style.opacity=0.6); }
    else { [btnInsertHead, btnInsertTail, btnDelete, btnSearch, btnReset, btnRandom].forEach(b=>b.style.opacity=1); }
  }

  function sleep(ms){ return new Promise(resolve=>setTimeout(resolve, ms)); }

  // event wiring
  btnInsertHead.addEventListener('click', async ()=>{
    const v = input.value.trim();
    if(v === '') { flashStatus('Enter a value', true); return; }
    await visualInsertHead(v);
    input.value = '';
  });
  btnInsertTail.addEventListener('click', async ()=>{
    const v = input.value.trim();
    if(v === '') { flashStatus('Enter a value', true); return; }
    await visualInsertTail(v);
    input.value = '';
  });
  btnDelete.addEventListener('click', async ()=>{
    const v = input.value.trim();
    if(v === '') { flashStatus('Enter a value', true); return; }
    await visualDelete(v);
    input.value = '';
  });
  btnSearch.addEventListener('click', async ()=>{
    const v = input.value.trim();
    if(v === '') { flashStatus('Enter a value', true); return; }
    await visualSearch(v);
    input.value = '';
  });
  btnReset.addEventListener('click', ()=>{
    list.clear();
    render();
  });
  btnRandom.addEventListener('click', ()=>{
    // demo: populate a few nodes
    list.clear();
    const demo = ['A','B','C','D','E'];
    for(const x of demo) list.insertTail(x);
    render();
    flashStatus('Demo list created', false);
  });

  // initial render
  render();

  // enable mouse wheel zoom in the viz area
  (function enableZoom(){
    let scale = 1;
    let viewBox = svg.viewBox.baseVal;
    viz.addEventListener('wheel', (e)=>{
      if(e.ctrlKey || e.metaKey) return;
      e.preventDefault();
      const delta = -e.deltaY;
      const factor = delta > 0 ? 1.08 : 0.92;
      scale = Math.max(0.4, Math.min(2.6, scale * factor));
      // update viewBox to zoom around center
      const vbWidth = viewBox.width / factor;
      const cx = viewBox.x + viewBox.width/2;
      const cy = viewBox.y + viewBox.height/2;
      viewBox.x = cx - vbWidth/2;
      viewBox.y = cy - viewBox.height/2;
      viewBox.width = Math.max(600, viewBox.width / factor);
      viewBox.height = viewBox.height;
      svg.setAttribute('viewBox', `${viewBox.x} ${viewBox.y} ${viewBox.width} ${viewBox.height}`);
    }, { passive:false });
  })();

})();
</script>
```

Notes:
- Nodes are drawn as grouped SVG elements with a left value box and a small "next" box on the right; arrows are smooth Bezier curves with an arrowhead marker so arrows remain connected even if nodes move.
