        <div class="card" aria-label="Preferences">
          <h3>Preferences</h3>
          <label for="persist">Persist theme</label>
          <select id="persist">
            <option value="none">Don't save</option>
            <option value="local">LocalStorage</option>
          </select>

          <div style="margin-top:12px;">
            <label>System preference</label>
            <div id="systemPref" class="muted">Detecting…</div>
          </div>
        </div>

        <footer>
          <div>Built with a singleton ThemeManager. Demo only.</div>
        </footer>
