    ctx.clearRect(0,0,canvas.width,canvas.height);
  }

  function drawBackground() {
    const gw = canvas.width / (window.devicePixelRatio || 1);
    const gh = canvas.height / (window.devicePixelRatio || 1);
    const g = ctx.createLinearGradient(0,0,0,gh);
    g.addColorStop(0, '#f8fdfb');
    g.addColorStop(1, '#e9f1ff');
    ctx.fillStyle = g;
    ctx.fillRect(0,0,gw,gh);
  }

  function drawLine(x1,y1,x2,y2, width, color) {
    ctx.strokeStyle = color || '#3b2';
    ctx.lineWidth = Math.max(0.5, width || 1);
    ctx.beginPath();
    ctx.moveTo(x1,y1);
    ctx.lineTo(x2,y2);
    ctx.stroke();
  }

  // Recursive implementation: draw branch from (x,y) in direction 'angle' radians with given length and depth.
  function drawBranchRecursive(x, y, angleRad, length, depth, maxDepth, shrink, branchWidth) {
    // base case
    if (depth > maxDepth) return;
    // compute endpoint
    const x2 = x + Math.cos(angleRad) * length;
    const y2 = y + Math.sin(angleRad) * length;
    // color and width depend on depth
    const t = depth / maxDepth;
    const color = depth > maxDepth*0.6 ? '#2b542b' : '#7b4225';
    drawLine(x, y, x2, y2, branchWidth, color);

    // reduce length and width for children
    const nextLength = length * shrink;
    const nextWidth = Math.max(0.5, branchWidth * 0.72);

    // recursive step: two children at +/- angle
    const a = angleRad;
    const spread = angleRad._spread || 0; // not used; angle is passed directly
    // left child
    drawBranchRecursive(x2, y2, a - angleForChildren, nextLength, depth + 1, maxDepth, shrink, nextWidth);
    // right child
    drawBranchRecursive(x2, y2, a + angleForChildren, nextLength, depth + 1, maxDepth, shrink, nextWidth);
  }

  // Iterative implementation using an explicit stack (objects)
  function drawBranchIterative(x, y, angleRad, length, maxDepth, shrink, branchWidth) {
    // stack holds frames: {x, y, angle, length, depth, width}
    const stack = [{ x, y, angle: angleRad, length, depth: 1, width: branchWidth }];
    while (stack.length) {
      const frame = stack.pop();
      const { x: fx, y: fy, angle, length: flen, depth, width } = frame;
      if (depth > maxDepth) continue;
      const x2 = fx + Math.cos(angle) * flen;
