      drawLine(fx, fy, x2, y2, width, color);

      const nextLength = flen * shrink;
      const nextWidth = Math.max(0.5, width * 0.72);
      // push right then left so left is processed first (LIFO)
      stack.push({ x: x2, y: y2, angle: angle + angleForChildren, length: nextLength, depth: depth + 1, width: nextWidth });
