    // When a worker wants to propose an update, it queues an updater function that receives the current value,
    // computes the new value, and returns it. The queue ensures updates see the effect of previous updates.
    const updateQueue = [];
    let processing = false;

    function enqueueUpdate(updater, debugLabel){
      return new Promise((resolve) => {
        updateQueue.push({updater,resolve,debugLabel});
        processQueue();
