      }

      // safety stop
      setTimeout(()=>{ running = false; log(logEl,'[FIXED] stopped by timer.'); }, 20000);
    }

    function resetAll(){
      running = false;
      progressValue = 0;
      render();
      logEl.textContent = '';
    }

