      }
      return tasks;
    }

    // A more deterministic simulation that returns per-task multiple events (instead of single resolvable promise)
    // We'll instead create a function that takes a per-task callback to call multiple times asynchronously:
    function runSimulatedTaskEvents(count, perEventCb){
      for(let i=0;i<count;i++){
        const id = i+1;
        const updates = 1 + Math.floor(Math.random()*3); // 1..3 updates per task
        for(let k=0;k<updates;k++){
          const delay = 50 + Math.floor(Math.random()*400) + (k*30);
          (function(id, k, updates){
            setTimeout(() => {
              const chunk = Math.max(1, Math.floor(Math.random()*15)); // contribution chunk percent-ish
              const done = (k === updates-1);
              perEventCb({ id, chunk, done, k, updates, when: Date.now() });
            }, delay);
