      const bar = el('fix-bar');
      const log = el('fix-log');
      const start = el('fix-start');
      const reset = el('fix-reset');

      let totalPercent = 0;
      let running = false;

      function appendLog(msg){
        logTo(log, '[' + new Date().toLocaleTimeString() + '] ' + msg);
      }

      // A simple "mutex" implemented with promises: ensures only one updater runs the critical section at a time.
      // Note: In single-threaded JS this pattern serializes async updates to avoid read-then-write races.
      function createLock(){
        let tail = Promise.resolve();
        return {
          runExclusive: function(fn){
            const myTurn = tail;
            let release;
            tail = new Promise((res) => { release = res; });
            // chain: wait for previous, run, then release
            return myTurn.then(() => {
              try {
                return Promise.resolve(fn());
              } finally {
                release();
              }
            });
          }
        };
      }

      const lock = createLock();

