          // schedule the atomic update using the lock
          lock.runExclusive(() => {
            // this function runs without interleaving with other runExclusive bodies
            const before = totalPercent;
            const after = Math.min(100, before + event.chunk); // clamp to 100
            totalPercent = after;
            appendLog('Atomic update applied: before=' + before + ' + chunk=' + event.chunk + ' => after=' + totalPercent);
            setBar(bar, totalPercent);
          }).catch((err) => {
            appendLog('Error in atomic update: ' + err);
          });
        });

        // finalization
        setTimeout(() => {
          appendLog('Fixed run finished. Final totalPercent = ' + totalPercent + '%.');
          running = false;
        }, 2000);
      }

      function fixedReset(){
        totalPercent = 0;
        setBar(bar, 0);
        log.textContent = '';
        appendLog('Reset totalPercent to 0%');
