  // Utility: compute Fibonacci sequence up to n (inclusive)
  // correctBase: if true, fib(0)=0, fib(1)=1; if false (buggy), fib(0)=1, fib(1)=1
  function fibSequence(n, correctBase = true) {
    const f = [];
    if (n < 0) return f;
    if (correctBase) {
      f[0] = 0;
      if (n === 0) return f;
      f[1] = 1;
    } else {
      // Bug: both base cases = 1 (often mistaken when coder thinks 0th term should be 1)
      f[0] = 1;
      if (n === 0) return f;
      f[1] = 1;
    }
    for (let i = 2; i <= n; i++) f[i] = f[i-1] + f[i-2];
    return f;
  }

