  // options:
  //   steps: number of squares to draw (>=1)
  //   scale: scale factor to convert fib units to pixels
  //   showGrid: draw grid lines for squares
  //   correctBase: whether to use correct fib base cases
  function drawFibonacci(canvas, options = {}) {
    const ctx = canvas.getContext('2d');
    const w = canvas.width, h = canvas.height;
    ctx.clearRect(0,0,w,h);

    const steps = options.steps || 9;
    const scale = options.scale || 6;
    const showGrid = options.showGrid !== false;
    const correctBase = options.correctBase !== false;

    // Compute sequence of side lengths (we'll start at index 1 to get positive sizes)
    // We'll compute up to steps (so we have steps squares). Use fibSequence(steps)
    const seq = fibSequence(steps, correctBase).slice(1); // drop index 0 for drawing squares
    // seq[0] corresponds to fib(1)

    // If seq lengths get too big for canvas, adjust scale
    const totalSpan = seq.reduce((a,b)=>a+b, 0); // rough bounding box size along one axis if all added
    // center drawing
