    // Start at center, place the first square such that its center is near center.
    // Use a simple algorithm: maintain current top-left position of bounding box,
    // and orientation 0..3 indicating direction of next square.
    const squares = []; // {x,y,size} top-left coords in canvas pixels

    // Convert fib units to pixels
    const sizes = seq.map(s => s * scale);

    // Start with first square centered
    let x = Math.round(centerX - sizes[0]/2);
    let y = Math.round(centerY - sizes[0]/2);
    squares.push({x,y,size:sizes[0]});

    // orientation: 0 = right (place square to right of current), 1 = down, 2 = left, 3 = up.
    // We'll maintain an outer bounding box for placement to know where new square goes.
    let minX = x, minY = y, maxX = x + sizes[0], maxY = y + sizes[0];

    for (let i = 1; i < sizes.length; i++) {
      const s = sizes[i];
      const dir = (i-1) & 3; // rotate through 0..3. Using (i-1) so second square uses dir 0 etc.
      let nx, ny;
      if (dir === 0) {
        // place to the right of current bounding box, aligned to top or overlapping appropriately
        nx = maxX;
        // align vertically so square's top matches minY
        ny = minY;
      } else if (dir === 1) {
        // place below bounding box
        nx = minX;
        ny = maxY;
      } else if (dir === 2) {
        // place to the left
        nx = minX - s;
        ny = minY + (maxY - minY) - s; // align bottom
      } else {
        // place above
        nx = minX + (maxX - minX) - s; // align right
        ny = minY - s;
      }
      squares.push({x: nx, y: ny, size: s});
      // update bounds
      minX = Math.min(minX, nx);
      minY = Math.min(minY, ny);
      maxX = Math.max(maxX, nx + s);
      maxY = Math.max(maxY, ny + s);
    }

    // Optionally draw grid of squares
    if (showGrid) {
      ctx.strokeStyle = '#bbb';
      ctx.lineWidth = 1;
      for (const sq of squares) {
        ctx.strokeRect(Math.round(sq.x)+0.5, Math.round(sq.y)+0.5, Math.round(sq.size), Math.round(sq.size));
      }
    }

    // Draw arcs (quarter circles) inside each square to form the spiral.
    // The arc for square i has radius equal to its size (in pixels) and centered at a corner
    // of that square. We must choose center and start/end angles based on orientation.
    ctx.strokeStyle = '#c33';
    ctx.lineWidth = 2;
    ctx.beginPath();
    for (let i = 0; i < squares.length; i++) {
      const sq = squares[i];
      const s = sq.size;
      // Determine which corner to use and angles based on position relative to next square
      // Simpler: pick orientation rotation i%4 to choose corner and sweep.
      const rot = i & 3;
      let cx, cy, start, end;
      if (rot === 0) {
