        cx = sq.x;
        cy = sq.y + s;
        start = -Math.PI/2; end = 0; // from up to right
      } else if (rot === 1) {
        // center at top-left
        cx = sq.x;
        cy = sq.y;
        start = 0; end = Math.PI/2; // right to down
      } else if (rot === 2) {
        // center at top-right
        cx = sq.x + s;
        cy = sq.y;
        start = Math.PI/2; end = Math.PI; // down to left
      } else {
        // rot 3: center at bottom-right
        cx = sq.x + s;
        cy = sq.y + s;
        start = Math.PI; end = 3*Math.PI/2; // left to up
      }
      ctx.moveTo(cx + Math.cos(start)*s, cy + Math.sin(start)*s);
      ctx.arc(cx, cy, s, start, end, false);
    }
    ctx.stroke();

    // draw a small center marker
    ctx.fillStyle = '#000';
    ctx.fillRect(centerX-1, centerY-1, 2, 2);
  }

