    <div class="column leaking">
      <h2>Leaking version</h2>
      <div class="controls">
        <button id="leak-add">Add widget</button>
        <button id="leak-remove" class="danger">Remove last</button>
        <button id="leak-clear" class="danger">Remove all</button>
      </div>
      <div class="status">Tracked widget objects: <span id="leak-count" class="counter">0</span></div>
      <div class="note">Open DevTools -> Console to inspect retained objects. This page simulates retained references counter for demonstration.</div>
