      <h2>Fixed version</h2>
      <div class="controls">
        <button id="fix-add">Add widget</button>
        <button id="fix-remove" class="danger">Remove last</button>
        <button id="fix-clear" class="danger">Remove all</button>
      </div>
      <div class="status">Tracked widget objects: <span id="fix-count" class="counter">0</span></div>
      <div class="note">This version removes event listeners and clears references correctly on deletion.</div>
