<script>
(function(){
  // DOM refs
  const numTasksEl = document.getElementById('numTasks');
  const unitsEl = document.getElementById('unitsPerTask');
  const maxDelayEl = document.getElementById('maxDelay');
  const runBtn = document.getElementById('runBtn');
  const resetBtn = document.getElementById('resetBtn');
  const fixMethodEl = document.getElementById('fixMethod');

