  const bugFill = document.getElementById('bugFill');
  const bugPercent = document.getElementById('bugPercent');
  const bugExpected = document.getElementById('bugExpected');
  const bugFinal = document.getElementById('bugFinal');
  const bugStatus = document.getElementById('bugStatus');

  const fixLog = document.getElementById('fixLog');
  const fixFill = document.getElementById('fixFill');
  const fixPercent = document.getElementById('fixPercent');
  const fixExpected = document.getElementById('fixExpected');
  const fixFinal = document.getElementById('fixFinal');
  const fixStatus = document.getElementById('fixStatus');

  const delay = (ms)=> new Promise(r=>setTimeout(r,ms));

  function resetUI(){
    bugLog.textContent = '';
    fixLog.textContent = '';
    bugFill.style.width = '0%';
    fixFill.style.width = '0%';
    bugPercent.textContent = '0%';
    fixPercent.textContent = '0%';
    bugExpected.textContent = '0';
    fixExpected.textContent = '0';
    bugFinal.textContent = '0';
    fixFinal.textContent = '0';
    bugStatus.textContent = 'RUN';
    bugStatus.className = '';
    fixStatus.textContent = 'RUN';
    fixStatus.className = '';
  }

  resetBtn.addEventListener('click', resetUI);
