  runBtn.addEventListener('click', runDemo);

  function appendLog(el, text, cls){
    const line = document.createElement('div');
    if (cls) line.className = cls;
    line.textContent = text;
    el.appendChild(line);
    el.scrollTop = el.scrollHeight;
  }

  function runDemo(){
    resetUI();

    const n = Math.max(1, Math.floor(Number(numTasksEl.value) || 1));
    const units = Math.max(1, Math.floor(Number(unitsEl.value) || 1));
    const maxDelay = Math.max(1, Math.floor(Number(maxDelayEl.value) || 1));
    const expectedTotal = n * units;
    bugExpected.textContent = expectedTotal;
    fixExpected.textContent = expectedTotal;

    // Buggy shared state
    let bugShared = 0;

    // Fixed shared state
    let fixShared = 0;

    // For demonstration, spawn tasks that each "complete" `units` after a random delay.
