    function scheduleTasks(reportFn, logEl, label){
      for (let i=0;i<n;i++){
        const taskId = i+1;
        const d = Math.floor(Math.random()*maxDelay) + 5;
        setTimeout(() => {
          // Simulate some work steps that can interleave
          // We'll intentionally break the operation into read/compute/write with small micro-delays
          // to expose races.
          (async ()=>{
            appendLog(logEl, `[Task ${taskId}] start (delay ${d}ms)`);
            // read
            await delay(0); // yield to allow interleaving
            const observed = reportFn.peek ? reportFn.peek() : undefined;
            appendLog(logEl, `[Task ${taskId}] will add ${units} (observed=${observed})`);
            // compute then write via report function
            await delay(Math.random()*6); // more interleaving
            reportFn(units, taskId);
            appendLog(logEl, `[Task ${taskId}] reported +${units}`);
          })();
        }, d);
      }
    }

    // Buggy report function: read shared, compute, write (no synchronization)
    function bugReport(units, taskId){
      // read
      const old = bugShared;
      // simulate async gap that could have allowed other writes (we already yielded above)
      // compute
      const nw = old + units;
      // write
      bugShared = nw;
      // update UI
      const pct = Math.min(100, Math.round((bugShared / expectedTotal) * 100));
      bugFill.style.width = pct + '%';
      bugPercent.textContent = pct + '%';
