    // Fix A: Actor queue (serializes updates by sending increments into an async queue)
    function makeActorReporter(){
      let state = 0;
      const queue = [];
      let running = false;
      function scheduleApply(delta, taskId){
        return new Promise(resolve=>{
          queue.push({delta, taskId, resolve});
          if (!running) drain();
        });
      }
      async function drain(){
        running = true;
        while (queue.length){
          const {delta, taskId, resolve} = queue.shift();
          // apply
          const old = state;
          const nw = old + delta;
          // small async tick to simulate work
          await delay(0);
          state = nw;
          // update UI immediately
          const pct = Math.min(100, Math.round((state / expectedTotal) * 100));
          fixFill.style.width = pct + '%';
          fixPercent.textContent = pct + '%';
          resolve();
        }
        running = false;
      }
      const reporter = async (delta, taskId) => {
        await scheduleApply(delta, taskId);
      };
      reporter.peek = ()=>state;
      // allow reading final state later
      reporter.getState = ()=>state;
      return reporter;
