        return withLock(async ()=>{
          const old = state;
          // small yield
          await delay(0);
          state = old + delta;
          const pct = Math.min(100, Math.round((state / expectedTotal) * 100));
          fixFill.style.width = pct + '%';
          fixPercent.textContent = pct + '%';
