        ...brokenCart.map(it => it.name + " -> " + it.price.toFixed(20))
      ];
      dbgBroken.push("");
      dbgBroken.push("Example: 4.99 as Number -> " + (4.99).toFixed(20));
      dbgBroken.push("Example: 0.01 as Number -> " + (0.01).toFixed(20));
      dbgBroken.push("4.99 + 0.01 -> " + (4.99 + 0.01).toFixed(20));
      document.getElementById("brokenDebug").textContent = dbgBroken.join("\n");

      // Fixed table
      const fixedTbody = document.querySelector("#fixedTable tbody");
