<script>
/*
  Simple shopping cart demo showing differences:

  - The "broken" cart stores prices as Numbers (floating point) and compares using ===.
  - The "fixed" cart stores prices as integer cents (Number integers) and uses integer arithmetic.
  - bigInt version uses BigInt for cents to emphasize whole-integer arithmetic without rounding.
*/

// Cart data structures
const cart = []; // items as {name, priceStr, priceFloat, qty}
const cartCents = []; // items as {name, cents, qty}
const cartCentsBigInt = []; // items as {name, centsBigInt, qty}

function parsePriceToFloat(priceStr) {
  // Naive parse using Number (or parseFloat)
  return Number(priceStr);
}

function parsePriceToCents(priceStr) {
  // Convert via string to avoid floating point rounding when converting.
  // Steps:
  //  - Normalize decimal point (no thousands separators).
  //  - Ensure at most two decimal places by padding/truncating (rounding not performed here except truncation).
  //  - Multiply integer-part and fractional part accordingly.
  // This returns a Number that is an integer (safe for typical money up to large amounts).
  const s = String(priceStr).trim();
  if (!s) return 0;
  // Allow leading +, -, handle negative
  let sign = 1;
  let t = s;
  if (t[0] === '+') t = t.slice(1);
  if (t[0] === '-') { sign = -1; t = t.slice(1); }
  // Reject non-numeric quickly (very basic)
  if (!/^\d+(\.\d+)?$/.test(t)) {
    // fallback: try Number then round
    const n = Number(s);
    if (Number.isFinite(n)) return Math.round(n * 100) * sign;
    return 0;
  }
  let [whole, frac] = t.split('.');
  frac = frac || '';
  if (frac.length > 2) {
    // round to 2 decimals (standard rounding)
    const third = Number(frac[2]);
    frac = frac.slice(0,2);
    if (third >= 5) {
      let asNum = Number(whole) * 100 + Number(frac) + 1;
      return sign * asNum;
    }
  }
  while (frac.length < 2) frac += '0';
  return sign * (Number(whole) * 100 + Number(frac));
}

function parsePriceToCentsBigInt(priceStr) {
  const s = String(priceStr).trim();
  if (!s) return 0n;
  let sign = 1n;
  let t = s;
  if (t[0] === '+') t = t.slice(1);
  if (t[0] === '-') { sign = -1n; t = t.slice(1); }
  if (!/^\d+(\.\d+)?$/.test(t)) {
    const n = Number(s);
    if (Number.isFinite(n)) return BigInt(Math.round(n * 100)) * sign;
    return 0n;
  }
  let [whole, frac] = t.split('.');
  frac = frac || '';
  if (frac.length > 2) {
    const third = Number(frac[2]);
    frac = frac.slice(0,2);
    if (third >= 5) {
      let asNum = BigInt(whole) * 100n + BigInt(frac) + 1n;
      return sign * asNum;
    }
  }
  while (frac.length < 2) frac += '0';
  return sign * (BigInt(whole) * 100n + BigInt(frac));
}

function formatCents(cents) {
  const sign = cents < 0 ? '-' : '';
  cents = Math.abs(cents);
  const dollars = Math.floor(cents / 100);
  const rem = String(cents % 100).padStart(2, '0');
  return sign + '$' + dollars + '.' + rem;
}

function formatCentsBigInt(centsBigInt) {
  const sign = centsBigInt < 0n ? '-' : '';
  const a = centsBigInt < 0n ? -centsBigInt : centsBigInt;
  const dollars = a / 100n;
  const rem = a % 100n;
  return sign + '$' + dollars.toString() + '.' + rem.toString().padStart(2, '0');
}

// UI helpers
const itemNameEl = document.getElementById('itemName');
const itemPriceEl = document.getElementById('itemPrice');
const itemQtyEl = document.getElementById('itemQty');
const addBtn = document.getElementById('addBtn');
const cartArea = document.getElementById('cartArea');
const clearBtn = document.getElementById('clearBtn');

