  // broken
  const floatVal = parsePriceToFloat(priceStr);
  cart.push({name, priceStr, priceFloat: floatVal, qty});
  // fixed cents (Number)
  const cents = parsePriceToCents(priceStr);
  cartCents.push({name, cents, qty});
  // BigInt version
  const centsBI = parsePriceToCentsBigInt(priceStr);
  cartCentsBigInt.push({name, centsBI, qty});
  renderCart();
  renderTotals();
});

clearBtn.addEventListener('click', () => {
  cart.length = 0;
  cartCents.length = 0;
  cartCentsBigInt.length = 0;
  renderCart();
  renderTotals();
});

function renderCart() {
  if (cart.length === 0) {
    cartArea.innerHTML = '<em>Cart is empty</em>';
    return;
  }
  let html = '<table><thead><tr><th>name</th><th>price (string)</th><th>price (float)</th><th>qty</th></tr></thead><tbody>';
  for (let i = 0; i < cart.length; i++) {
    const it = cart[i];
    html += `<tr><td>${escapeHtml(it.name)}</td><td class="ft">${escapeHtml(it.priceStr)}</td><td class="ft">${it.priceFloat} (${typeof it.priceFloat})</td><td>${it.qty}</td></tr>`;
  }
  html += '</tbody></table>';
  cartArea.innerHTML = html;
}

function renderTotals() {
