  brokenResult.innerHTML = '';
  const br = document.createElement('div');
  br.innerHTML = `<div>Sum using Number (float) and + : <span class="ft">${totalFloat}</span></div>
                  <div>Formatted (toFixed(2)) : <span class="ft">${totalFloat.toFixed(2)}</span></div>
                  <div>Does any item === ${searchPrice}? : <span class="${foundBroken ? 'ok' : 'bad'}">${foundBroken}</span></div>`;
  brokenResult.appendChild(br);

  // Fixed (cents) total
  let totalCents = 0;
  for (const it of cartCents) {
    totalCents += it.cents * it.qty;
  }
  fixedResult.innerHTML = `<div>Sum in integer cents: <span class="ft">${totalCents}</span></div>
                           <div>Formatted: <span class="ft">${formatCents(totalCents)}</span></div>`;

  // BigInt
  let totalCentsBI = 0n;
  for (const it of cartCentsBigInt) {
    totalCentsBI += it.centsBI !== undefined ? it.centsBI * BigInt(it.qty) : it.centsBigInt * BigInt(it.qty);
    // ensure either property name works; our items used centsBI sometimes
  }
  // compatible loop without relying on property names:
  totalCentsBI = 0n;
  for (const it of cartCentsBigInt) {
    const v = it.centsBigInt !== undefined ? it.centsBigInt : (it.centsBI !== undefined ? it.centsBI : 0n);
    totalCentsBI += v * BigInt(it.qty);
  }
  bigintResult.innerHTML = `<div>Sum in cents (BigInt): <span class="ft">${totalCentsBI}n</span></div>
                            <div>Formatted: <span class="ft">${formatCentsBigInt(totalCentsBI)}</span></div>`;
}

